# Python
#!/usr/bin/env python3
"""
Capacity Estimation Calculator
Estimates infrastructure requirements for a scalable service
"""

class CapacityEstimator:
    def __init__(self, registered_users, dau_percentage, req_per_user_per_day):
        self.registered_users = registered_users
        self.dau = registered_users * (dau_percentage / 100)
        self.req_per_user = req_per_user_per_day

    def calculate_qps(self, peak_multiplier=4):
        """Calculate average and peak queries per second"""
        avg_qps = (self.dau * self.req_per_user) / 86400
        peak_qps = avg_qps * peak_multiplier
        return {"avg": avg_qps, "peak": peak_qps}

    def calculate_storage(self, bytes_per_user, retention_years, replication=3):
        """Calculate total storage needed"""
        raw_storage = self.dau * bytes_per_user * retention_years
        total_storage = raw_storage * replication
        return {"raw_gb": raw_storage / (1024**3), "total_gb": total_storage / (1024**3)}

    def server_count(self, peak_qps, capacity_per_server=50000, redundancy=2):
        """Calculate server count with redundancy"""
        base_servers = peak_qps / capacity_per_server
        total_servers = base_servers * redundancy
        return int(total_servers)

# Example: Instagram-scale system
estimator = CapacityEstimator(
    registered_users=1_000_000_000,
    dau_percentage=15,
    req_per_user_per_day=50
)

qps = estimator.calculate_qps(peak_multiplier=5)
print(f"Avg QPS: {qps["avg"]:,.0f}")
print(f"Peak QPS: {qps["peak"]:,.0f}")

