    this.registeredUsers = registeredUsers;
    this.dau = registeredUsers * (dauPercentage / 100);
    this.reqPerUser = reqPerUserPerDay;
  }

  calculateQPS(peakMultiplier = 4) {
    const avgQps = (this.dau * this.reqPerUser) / 86400;
    const peakQps = avgQps * peakMultiplier;
    return { avg: avgQps, peak: peakQps };
  }

  calculateStorage(bytesPerUser, retentionYears, replication = 3) {
    const rawStorage = this.dau * bytesPerUser * retentionYears;
    const totalStorage = rawStorage * replication;
    return {
      rawGB: rawStorage / Math.pow(1024, 3),
      totalGB: totalStorage / Math.pow(1024, 3)
    };
  }

  serverCount(peakQps, capacityPerServer = 50000, redundancy = 2) {
    const baseServers = peakQps / capacityPerServer;
    return Math.ceil(baseServers * redundancy);
  }
}

