# Go
package main

import (
	"fmt"
	"math"
)

type CapacityEstimate struct {
	AvgQPS  float64
	PeakQPS float64
}

type CapacityEstimator struct {
	dau        float64
	reqPerUser float64
}

func NewCapacityEstimator(registered, dauPercent, reqPerDay float64) *CapacityEstimator {
	dau := registered * (dauPercent / 100.0)
	return &CapacityEstimator{dau: dau, reqPerUser: reqPerDay}
}

func (ce *CapacityEstimator) Estimate(peakMultiplier float64) *CapacityEstimate {
	avgQPS := (ce.dau * ce.reqPerUser) / 86400.0
	peakQPS := avgQPS * peakMultiplier
	return &CapacityEstimate{AvgQPS: avgQPS, PeakQPS: peakQPS}
}

func main() {
	estimator := NewCapacityEstimator(2e9, 12, 75)
	estimate := estimator.Estimate(5)
	fmt.Printf("Peak QPS: %.0f\n", estimate.PeakQPS)
}

