  }

  CapacityEstimate estimate(double peak_multiplier = 4.0) {
    CapacityEstimate result;
    result.avg_qps = (dau * req_per_user) / 86400.0;
    result.peak_qps = result.avg_qps * peak_multiplier;
    return result;
  }
};

