// TinyURL Node.js Implementation

const redis = require('redis');
const pool = require('mysql2/promise');

class TinyURL {
  constructor(dbPool, redisClient) {
    this.db = dbPool;
    this.cache = redisClient;
    this.BASE62 = '0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ';
    this.CACHE_TTL = 86400; // 24 hours
  }

  encodeBase62(num) {
    if (num === 0) return this.BASE62[0];
    const digits = [];
    while (num > 0) {
      digits.push(this.BASE62[num % 62]);
      num = Math.floor(num / 62);
    }
    return digits.reverse().join('');
  }

  async shorten(longUrl, customCode = null) {
    if (customCode) {
      // Check collision in cache and DB
      const exists = await this.cache.get(`url:${customCode}`);
      if (exists) throw new Error('Custom code already taken');
      const [rows] = await this.db.query(
        'SELECT id FROM urls WHERE short_url = ?',
        [customCode]
      );
      if (rows.length > 0) throw new Error('Custom code already taken');
      var shortCode = customCode;
    } else {
      // Insert URL and encode ID
      const [result] = await this.db.query(
        'INSERT INTO urls (long_url) VALUES (?)',
        [longUrl]
      );
      shortCode = this.encodeBase62(result.insertId);
      // Update short_url column
      await this.db.query(
        'UPDATE urls SET short_url = ? WHERE id = ?',
        [shortCode, result.insertId]
      );
    }

    // Cache bidirectional mapping
    await this.cache.setEx(`url:${shortCode}`, this.CACHE_TTL, longUrl);
    await this.cache.setEx(`code:${longUrl}`, this.CACHE_TTL, shortCode);
    return shortCode;
  }

  async redirect(shortCode) {
    // Check cache first (hot path)
    const cached = await this.cache.get(`url:${shortCode}`);
    if (cached) {
      this.queueAnalytics(shortCode); // async, non-blocking
      return cached;
    }

    // Cache miss: query database
    const [rows] = await this.db.query(
      'SELECT long_url FROM urls WHERE short_url = ?',
      [shortCode]
    );
    if (rows.length === 0) return null;

    const longUrl = rows[0].long_url;
    // Update cache
    await this.cache.setEx(`url:${shortCode}`, this.CACHE_TTL, longUrl);

    // Async: increment click count
    this.queueAnalytics(shortCode);
    return longUrl;
  }

  async queueAnalytics(shortCode) {
    // Async queue to message broker (Kafka, RabbitMQ)
    // For production: queue to external message queue
    // For now: use Redis counter with periodic batch writes
    const key = `analytics:${shortCode}`;
    await this.cache.incr(key);
    // Batch write to DB periodically (every minute)
  }
}

module.exports = TinyURL;

