// Pastebin Node.js Implementation

const redis = require('redis');
const pool = require('mysql2/promise');
const zlib = require('zlib');
const { v4: uuidv4 } = require('uuid');
const AWS = require('aws-sdk');

class Pastebin {
  constructor(dbPool, redisClient, s3Client) {
    this.db = dbPool;
    this.cache = redisClient;
    this.s3 = s3Client;
    this.CACHE_TTL = 86400; // 24 hours
    this.HOT_TIER_DAYS = 30;
  }

  async createPaste(content, language, {
    title = null,
    expiresHours = null,
    visibility = 'PUBLIC',
    userId = null
  } = {}) {
    // Compress content
    const compressed = zlib.gzipSync(content);
    const contentToStore = compressed.length < Buffer.byteLength(content) 
      ? { data: compressed, isCompressed: true }
      : { data: Buffer.from(content), isCompressed: false };

    // Generate unique short code
    const shortCode = await this._generateShortCode();

    // Calculate expiration
    let expiresAt = null;
    if (expiresHours) {
      expiresAt = new Date(Date.now() + expiresHours * 3600000);
    }

    // Store in DB
    const [result] = await this.db.query(
      `INSERT INTO pastes 
       (user_id, short_code, title, content, language, expires_at, visibility, is_compressed)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?)`,
      [userId, shortCode, title, contentToStore.data, language, expiresAt, visibility, contentToStore.isCompressed]
    );

    // Cache the paste
    const cacheData = JSON.stringify({
      content,
      language,
      title: title || '',
      visibility,
      viewCount: 0,
      createdAt: new Date().toISOString()
    });
    await this.cache.setEx(`paste:${shortCode}`, this.CACHE_TTL, cacheData);

    return shortCode;
  }

  async getPaste(shortCode, userId = null) {
    // Check cache first (hot path)
    const cached = await this.cache.get(`paste:${shortCode}`);
    if (cached) {
      const pasteData = JSON.parse(cached);
      // Check visibility
      if (!this._checkAccess(pasteData.visibility, userId)) {
        return null;
      }
      // Async increment view count
      this.cache.incr(`views:${shortCode}`).catch(console.error);
      return pasteData;
    }

    // Cache miss: fetch from DB
    const [rows] = await this.db.query(
      `SELECT id, content, language, title, visibility, is_compressed, view_count, created_at
       FROM pastes WHERE short_code = ?`,
      [shortCode]
    );

    if (rows.length === 0) return null;

    const { id, content, language, title, visibility, is_compressed, view_count, created_at } = rows[0];

    // Check visibility
    if (!this._checkAccess(visibility, userId)) {
      return null;
    }

    // Decompress if needed
    let decompressed = content;
    if (is_compressed) {
      decompressed = zlib.gunzipSync(content).toString();
    } else if (Buffer.isBuffer(content)) {
      decompressed = content.toString();
    }

    // Update cache
    const cacheData = JSON.stringify({
      content: decompressed,
      language,
      title: title || '',
      visibility,
      viewCount: view_count,
      createdAt: created_at.toISOString()
    });
    await this.cache.setEx(`paste:${shortCode}`, this.CACHE_TTL, cacheData);

    // Async view count increment
    this.cache.incr(`views:${shortCode}`).catch(console.error);

    return JSON.parse(cacheData);
  }

  async _generateShortCode() {
    let shortCode;
    let exists = true;

    while (exists) {
      // Generate 8-char random code
      shortCode = uuidv4().replace(/-/g, '').substring(0, 8);

      // Check collision
      const [rows] = await this.db.query(
        'SELECT id FROM pastes WHERE short_code = ?',
        [shortCode]
      );
      exists = rows.length > 0;
    }

    return shortCode;
  }

  _checkAccess(visibility, userId) {
    if (visibility === 'PUBLIC' || visibility === 'UNLISTED') {
      return true;  // Anyone with link
    }
    if (visibility === 'PRIVATE') {
      return userId !== null;  // Owner only
    }
    return false;
  }

  async archiveExpiredPastes() {
    """Move expired pastes to S3 and delete from DB. Run hourly."""
    const [rows] = await this.db.query(
      `SELECT id, short_code, content FROM pastes 
       WHERE expires_at < NOW() AND archived_at IS NULL
       LIMIT 1000`
    );

    for (const { id, short_code, content } of rows) {
      // Archive to S3
      const key = `pastes/archived/${short_code}.gz`;
      await this.s3.putObject({
        Bucket: 'pastebin-archive',
        Key: key,
        Body: content,
        ContentEncoding: 'gzip'
      }).promise();

      // Mark archived
      await this.db.query(
        'UPDATE pastes SET archived_at = NOW() WHERE id = ?',
        [id]
      );
      await this.cache.del(`paste:${short_code}`);
    }
  }
}

