// Instagram Node.js Implementation

const redis = require('redis');
const pool = require('mysql2/promise');
const { Kafka } = require('kafkajs');

const NotificationType = {
  LIKE: 'like',
  COMMENT: 'comment',
  FOLLOW: 'follow',
  MENTION: 'mention'
};

class Instagram {
  constructor(dbPool, redisClient, kafka) {
    this.db = dbPool;
    this.redis = redisClient;
    this.kafka = kafka;
    this.FEED_CACHE_TTL = 3600;      // 1 hour
    this.POST_CACHE_TTL = 86400;     // 24 hours
    this.FEED_SIZE = 1000;
    this.CELEBRITY_THRESHOLD = 10000;
  }

  async createPost(userId, caption, imageUrlOriginal, imageUrlFeed, imageUrlThumb) {
    const [result] = await this.db.query(
      `INSERT INTO posts (user_id, caption, image_url_original, image_url_feed, 
       image_url_thumb, created_at) VALUES (?, ?, ?, ?, ?, NOW())`,
      [userId, caption, imageUrlOriginal, imageUrlFeed, imageUrlThumb]
    );

    const postId = result.insertId;

    // Fanout post to followers
    await this._fanoutPost(userId, postId);

    // Cache post metadata
    const postData = {
      id: postId,
      userId,
      caption,
      likeCount: 0,
      commentCount: 0,
      createdAt: new Date().toISOString()
    };
    await this.redis.setEx(`post:${postId}`, this.POST_CACHE_TTL, JSON.stringify(postData));

    return postId;
  }

  async _fanoutPost(userId, postId) {
    // Check if user is celebrity
    const [rows] = await this.db.query(
      'SELECT followers_count FROM users WHERE id = ?',
      [userId]
    );
    const followersCount = rows[0]?.followers_count || 0;

    if (followersCount < this.CELEBRITY_THRESHOLD) {
      // Regular user: fanout to all followers
      const [followers] = await this.db.query(
        'SELECT follower_id FROM follows WHERE following_id = ?',
        [userId]
      );

      const score = Date.now() / 1000; // unix timestamp
      for (const { follower_id } of followers) {
        // Add post to follower's feed (sorted set)
        await this.redis.zAdd(`feed:${follower_id}`, { score, value: String(postId) });
        // Trim to top 1000
        await this.redis.zRemRangeByRank(`feed:${follower_id}`, this.FEED_SIZE, -1);
        // Invalidate feed cache
        await this.redis.del(`feed_posts:${follower_id}`);
      }
    }
    // Celebrity: don't fanout
  }

  async getFeed(userId, limit = 20, offset = 0) {
    // Check cache first
    const cachedFeed = await this.redis.get(`feed_posts:${userId}`);
    let postIds;

    if (cachedFeed) {
      postIds = JSON.parse(cachedFeed);
    } else {
      // Cache miss: reconstruct feed
      postIds = await this._buildFeed(userId);
      // Cache for 1 hour
      await this.redis.setEx(
        `feed_posts:${userId}`,
        this.FEED_CACHE_TTL,
        JSON.stringify(postIds)
      );
    }

    // Paginate
    const paginatedIds = postIds.slice(offset, offset + limit);

    // Fetch post metadata
    const posts = [];
    for (const postId of paginatedIds) {
      const cached = await this.redis.get(`post:${postId}`);
      if (cached) {
        posts.push(JSON.parse(cached));
      } else {
        // Fetch from DB
        const [rows] = await this.db.query(
          `SELECT id, user_id, caption, like_count, comment_count, 
           image_url_feed, created_at FROM posts WHERE id = ?`,
          [postId]
        );
        if (rows.length > 0) {
          const post = rows[0];
          const postDict = {
            id: post.id,
            userId: post.user_id,
            caption: post.caption,
            likeCount: post.like_count,
            commentCount: post.comment_count,
            imageUrl: post.image_url_feed,
            createdAt: post.created_at.toISOString()
          };
          await this.redis.setEx(`post:${postId}`, this.POST_CACHE_TTL, JSON.stringify(postDict));
          posts.push(postDict);
        }
      }
    }

    return posts;
  }

  async _buildFeed(userId) {
    // Get followed users
    const [following] = await this.db.query(
      'SELECT following_id FROM follows WHERE follower_id = ? LIMIT 5000',
      [userId]
    );

    if (following.length === 0) return [];

    const followingIds = following.map(f => f.following_id);
    const placeholders = followingIds.map(() => '?').join(',');

    // Fetch posts from followed users (chronological)
    const [posts] = await this.db.query(
      `SELECT id FROM posts WHERE user_id IN (${placeholders}) 
       ORDER BY created_at DESC LIMIT 1000`,
      followingIds
    );

    return posts.map(p => p.id);
  }

  async likePost(userId, postId) {
    try {
      await this.db.query(
        'INSERT INTO likes (post_id, user_id, created_at) VALUES (?, ?, NOW())',
        [postId, userId]
      );

      // Async: increment like count
      await this.redis.incr(`post_likes:${postId}`);

      // Get post owner
      const [rows] = await this.db.query('SELECT user_id FROM posts WHERE id = ?', [postId]);
      const postOwner = rows[0]?.user_id;

      // Publish to Kafka
      await this.kafka.producer.send({
        topic: 'likes',
        messages: [{
          value: JSON.stringify({
            postId,
            likerId: userId,
            postOwnerId: postOwner,
            timestamp: new Date().toISOString()
          })
        }]
      });
    } catch (e) {
      // Duplicate like
      console.error(e);
    }
  }

  async commentPost(userId, postId, content) {
    const [result] = await this.db.query(
      'INSERT INTO comments (post_id, user_id, content, created_at) VALUES (?, ?, ?, NOW())',
      [postId, userId, content]
    );
    const commentId = result.insertId;

    // Increment comment count
    await this.redis.incr(`post_comments:${postId}`);

    // Get post owner
    const [rows] = await this.db.query('SELECT user_id FROM posts WHERE id = ?', [postId]);
    const postOwner = rows[0]?.user_id;

    // Publish event
    await this.kafka.producer.send({
      topic: 'comments',
      messages: [{
        value: JSON.stringify({
          postId,
          commenterId: userId,
          commentId,
          postOwnerId: postOwner,
          timestamp: new Date().toISOString()
        })
      }]
    });

    return commentId;
  }

  async followUser(followerId, followingId) {
    try {
      await this.db.query(
        'INSERT INTO follows (follower_id, following_id, created_at) VALUES (?, ?, NOW())',
        [followerId, followingId]
      );

      // Update follower counts
      await this.db.query(
        'UPDATE users SET followers_count = followers_count + 1 WHERE id = ?',
        [followingId]
      );
      await this.db.query(
        'UPDATE users SET following_count = following_count + 1 WHERE id = ?',
        [followerId]
      );

      // Invalidate caches
      await Promise.all([
        this.redis.del(`user:${followerId}`),
        this.redis.del(`user:${followingId}`),
        this.redis.del(`feed_posts:${followerId}`)
      ]);

      // Publish notification
      await this.kafka.producer.send({
        topic: 'follows',
        messages: [{
          value: JSON.stringify({
            followerId,
            followingId,
            timestamp: new Date().toISOString()
          })
        }]
      });
    } catch (e) {
      // Duplicate follow
      console.error(e);
    }
  }
}

