# Python: Track Interview Feedback for Contradictions

class InterviewFeedback:
    def __init__(self, interviewer_name, role):
        self.interviewer = interviewer_name
        self.role = role
        self.feedback = {}

    def add_detail(self, category, detail):
        """Record what was said about a specific topic"""
        self.feedback[category] = detail

class ContradictionDetector:
    def __init__(self):
        self.interviews = []

    def add_interview(self, feedback):
        self.interviews.append(feedback)

    def find_contradictions(self):
        """Find all contradictions across interviews"""
        if len(self.interviews) < 2:
            return []

        contradictions = []
        all_categories = set()
        for interview in self.interviews:
            all_categories.update(interview.feedback.keys())

        for category in all_categories:
            responses = {}
            for interview in self.interviews:
                if category in interview.feedback:
                    response = interview.feedback[category]
                    if response not in responses:
                        responses[response] = []
                    responses[response].append(interview.interviewer)

            if len(responses) > 1:
                contradictions.append({
                    'category': category,
                    'responses': responses
                })

        return contradictions

    def print_report(self):
        """Print contradiction report"""
        contradictions = self.find_contradictions()
        if not contradictions:
            print('✅ No contradictions found')
            return

        print(f'🚩 Found {len(contradictions)} contradiction(s):')
        for item in contradictions:
            print(f'Category: {item["category"]}')
            for response, interviewers in item['responses'].items():
                print(f'  • {response}')
                print(f'    Said by: {", ".join(interviewers)}')

# Example Usage:
detector = ContradictionDetector()

