package debounce

import (
	"sync"
	"time"
)

// Debounce returns a function that delays invoking fn until after wait
// has elapsed since the last invocation.
func Debounce(fn func(), wait time.Duration) func() {
	var mu sync.Mutex
	var timer *time.Timer

	return func() {
		mu.Lock()
		defer mu.Unlock()
		if timer != nil {
			timer.Stop()
		}
		timer = time.AfterFunc(wait, fn)
	}
}

