// Leading-edge variant
function debounceLeading(fn, delay) {
    let timer = null;
    return function (...args) {
        if (!timer) fn.apply(this, args);  // fire immediately
        clearTimeout(timer);
        timer = setTimeout(() => { timer = null; }, delay);
    };
}

# Python
import threading

def debounce(delay: float):
    """Decorator that debounces a function by `delay` seconds."""
    def decorator(fn):
        timer: list[threading.Timer | None] = [None]

        def debounced(*args, **kwargs):
            if timer[0] is not None:
                timer[0].cancel()
            t = threading.Timer(delay, fn, args=args, kwargs=kwargs)
            t.daemon = True
            t.start()
            timer[0] = t

        return debounced
    return decorator


