# C++ - Observer Pattern (similar to Redux)
#include <functional>
#include <vector>

class Store {
  std::vector<std::function<void(const int&)>> listeners;
  int state = 0;

public:
  void subscribe(std::function<void(const int&)> listener) {
    listeners.push_back(listener);
  }

  void dispatch(const std::string& action, int payload) {
    if (action == "increment") {
      state += payload;
    }
    for (auto& listener : listeners) {
      listener(state);
    }
  }

  int getState() const { return state; }
};

# Rust - State Pattern
use std::sync::{Arc, Mutex};

struct Store {
    state: Arc<Mutex<i32>>,
}

impl Store {
    fn new() -> Self {
        Store { state: Arc::new(Mutex::new(0)) }
    }

    fn dispatch(&self, action: &str, payload: i32) {
        let mut state = self.state.lock().unwrap();
        match action {
            "increment" => *state += payload,
            "decrement" => *state -= payload,
            _ => {},
        }
    }

    fn get_state(&self) -> i32 {
        *self.state.lock().unwrap()
    }
}

# Go - State Pattern (similar to Redux)
type Store struct {
    state map[string]interface{}
    reducers map[string]func(map[string]interface{}, interface{}) map[string]interface{}
    listeners []func(map[string]interface{})
}

func (s *Store) Dispatch(action string, payload interface{}) {
    if reducer, ok := s.reducers[action]; ok {
        s.state = reducer(s.state, payload)
        s.notify()
    }
}

func (s *Store) Subscribe(listener func(map[string]interface{})) {
    s.listeners = append(s.listeners, listener)
}

func (s *Store) notify() {
    for _, listener := range s.listeners {
        listener(s.state)
    }
}

