# Middleware as decorator
def auth_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = request.headers.get('Authorization')
        if not token:
            return {'error': 'Missing token'}, 401
        g.user = {'id': 1, 'name': 'User'}
        return f(*args, **kwargs)
