    @wraps(f)
    def decorated_function(*args, **kwargs):
        start = time.time()
        result = f(*args, **kwargs)
        elapsed = time.time() - start
        print(f"Request took {elapsed:.3f}s")
        return result
    return decorated_function

@app.route('/api/data')
