using namespace std;

// Represents a customer segment
struct UserSegment {
    string name;
    string description;
    vector<string> painPoints;
    vector<string> valuePropositions;
    string estimatedMarketSize;
};

// Analyzes user segments and product-market fit
class CustomerAnalysis {
private:
    string companyName;
    map<string, UserSegment> segments;

public:
    CustomerAnalysis(const string& name) : companyName(name) {}

    void addSegment(const string& id, const UserSegment& segment) {
        segments[id] = segment;
    }

    // Calculate product-market fit for a segment
    double calculateFit(const UserSegment& segment) {
        if (segment.painPoints.empty()) return 0.0;

        // Count how many pain points have corresponding solutions
        int solutionsCount = min(segment.painPoints.size(), 
                                segment.valuePropositions.size());
        return static_cast<double>(solutionsCount) / segment.painPoints.size();
    }

    // Find the strongest segment
    pair<string, double> findStrongestSegment() {
        string bestSegment;
        double bestScore = 0.0;

        for (auto& [id, segment] : segments) {
            double score = calculateFit(segment);
            if (score > bestScore) {
                bestScore = score;
                bestSegment = id;
            }
        }

        return {bestSegment, bestScore};
    }

    void printAnalysis() {
        cout << "\n=== Customer Segment Analysis for " << companyName << " ===\n\n";

        for (auto& [id, segment] : segments) {
            cout << "Segment: " << segment.name << "\n";
            cout << "Description: " << segment.description << "\n";
            cout << "Market Size: " << segment.estimatedMarketSize << "\n";

            cout << "Pain Points:\n";
            for (const auto& pain : segment.painPoints) {
                cout << "  - " << pain << "\n";
            }

            cout << "Value Delivered:\n";
            for (const auto& value : segment.valuePropositions) {
                cout << "  - " << value << "\n";
            }

            double fit = calculateFit(segment);
            cout << "Product-Market Fit: " << (fit * 100) << "%\n\n";
        }
    }
};

