	ValueDelivered  []string
	EstimatedSize   string
}

// CompanyCustomerAnalysis analyzes user segments
type CompanyCustomerAnalysis struct {
	CompanyName string
	Segments    map[string]UserSegment
}

func NewCompanyAnalysis(name string) *CompanyCustomerAnalysis {
	return &CompanyCustomerAnalysis{
		CompanyName: name,
		Segments:    make(map[string]UserSegment),
	}
}

func (a *CompanyCustomerAnalysis) AddSegment(id string, segment UserSegment) {
	a.Segments[id] = segment
}

// AnalyzeProductMarketFit scores how well product meets segment needs
func (a *CompanyCustomerAnalysis) AnalyzeProductMarketFit() map[string]float64 {
	fit := make(map[string]float64)

	for name, segment := range a.Segments {
		painPointCount := len(segment.PainPoints)
		valueCount := len(segment.ValueDelivered)

		if painPointCount == 0 {
			fit[name] = 0
			continue
		}

		// Fit score: how many pain points are addressed
		fitScore := float64(valueCount) / float64(painPointCount)
		if fitScore > 1.0 {
			fitScore = 1.0 // Cap at 100%
		}
		fit[name] = fitScore
	}

	return fit
}

