# Rust
use std::collections::HashMap;

/// Represents a customer segment with identified pain points and solutions
#[derive(Clone, Debug)]
pub struct UserSegment {
    pub name: String,
    pub description: String,
    pub pain_points: Vec<String>,
    pub value_propositions: Vec<String>,
    pub estimated_size: String,
}

impl UserSegment {
    pub fn new(
        name: &str,
        description: &str,
        estimated_size: &str,
    ) -> Self {
        UserSegment {
            name: name.to_string(),
            description: description.to_string(),
            pain_points: Vec::new(),
            value_propositions: Vec::new(),
            estimated_size: estimated_size.to_string(),
        }
    }

    pub fn add_pain_point(mut self, pain: &str) -> Self {
        self.pain_points.push(pain.to_string());
        self
    }

    pub fn add_value(mut self, value: &str) -> Self {
        self.value_propositions.push(value.to_string());
        self
    }

    /// Calculate product-market fit score (0.0 to 1.0)
    pub fn fit_score(&self) -> f64 {
        if self.pain_points.is_empty() {
            return 0.0;
        }
        let aligned = std::cmp::min(self.pain_points.len(), self.value_propositions.len());
        aligned as f64 / self.pain_points.len() as f64
    }
}

/// Analyzes customer segments for a company
pub struct CustomerAnalysis {
    company_name: String,
    segments: HashMap<String, UserSegment>,
}

impl CustomerAnalysis {
    pub fn new(company_name: &str) -> Self {
        CustomerAnalysis {
            company_name: company_name.to_string(),
            segments: HashMap::new(),
        }
    }

    pub fn add_segment(&mut self, id: String, segment: UserSegment) {
        self.segments.insert(id, segment);
    }

    /// Find the segment with strongest product-market fit
    pub fn strongest_segment(&self) -> Option<(String, f64)> {
        self.segments
            .iter()
            .map(|(id, segment)| (id.clone(), segment.fit_score()))
            .max_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal))
    }

    /// Analyze all segments
    pub fn analyze(&self) -> HashMap<String, f64> {
        self.segments
            .iter()
            .map(|(id, segment)| (id.clone(), segment.fit_score()))
            .collect()
    }

    pub fn print_analysis(&self) {
        println!("\n=== Customer Analysis for {} ===", self.company_name);
        println!();

        for (id, segment) in &self.segments {
            println!("Segment: {}", segment.name);
            println!("  Description: {}", segment.description);
            println!("  Market Size: ~{}", segment.estimated_size);

            println!("  Pain Points:");
            for pain in &segment.pain_points {
                println!("    - {}", pain);
            }

            println!("  Value Delivered:");
            for value in &segment.value_propositions {
                println!("    - {}", value);
            }

            println!("  Product-Market Fit: {:.0}%\n", segment.fit_score() * 100.0);
        }
    }
}

fn main() {
    // Example: Analyzing a SaaS company's customer segments
    let mut analysis = CustomerAnalysis::new("Example SaaS Company");

    let segment1 = UserSegment::new(
        "Individual Developers",
        "Solo developers and small indie hackers",
        "Millions",
    )
    .add_pain_point("Complex setup for authentication")
    .add_pain_point("Managing multiple third-party services")
    .add_pain_point("Cost sensitivity")
    .add_value("Easy integration")
    .add_value("Freemium pricing")
    .add_value("Comprehensive documentation");

    let segment2 = UserSegment::new(
        "Enterprise Companies",
        "Large organizations with complex needs",
        "Thousands",
    )
    .add_pain_point("Security and compliance requirements")
    .add_pain_point("Integration with existing systems")
    .add_pain_point("Need for dedicated support")
    .add_value("Enterprise security features")
    .add_value("Custom integrations")
    .add_value("24/7 support");

    analysis.add_segment("dev".to_string(), segment1);
    analysis.add_segment("enterprise".to_string(), segment2);

    analysis.print_analysis();

    if let Some((segment, score)) = analysis.strongest_segment() {
