def assess_cultural_fit(company: dict, your_values: list) -> dict:
    """Assess alignment between your values and company's lived values."""
    alignment_score = sum(
        1 for your_val in your_values 
        if any(your_val.lower() in corp_val.lower() 
               for corp_val in company['core_values'])
    ) / len(your_values)
    return {
        "company": company['name'],
        "alignment_percentage": alignment_score * 100,
        "fit": "Strong" if alignment_score > 0.7 else "Moderate" if alignment_score > 0.4 else "Weak"
