    InterviewProcess(const std::string& comp, 
                     const std::vector<InterviewRound>& r,
                     const std::string& diff = "Medium")
        : company(comp), rounds(r), difficulty_level(diff) {}

    int getTotalTime() const {
        int total = 0;
        for (const auto& round : rounds) {
            total += round.duration_minutes;
        }
        return total;
    }

    int getPreparationHours() const {
        if (difficulty_level == "Hard") return 60;
        if (difficulty_level == "Easy") return 20;
        return 40;  // Medium
    }

    void printProcess() const {
        std::cout << company << ": " 
                  << getPreparationHours() << " hours recommended\n";
        std::cout << "Total interview time: " 
                  << getTotalTime() << " minutes\n";
        std::cout << "Rounds: ";
        for (size_t i = 0; i < rounds.size(); ++i) {
            if (i > 0) std::cout << " → ";
            std::cout << rounds[i].name;
        }
        std::cout << "\n";
    }
};

