#[derive(Clone, Debug)]
struct InterviewRound {
    name: String,
    duration_minutes: u32,
    focus_areas: Vec<String>,
}

#[derive(Debug)]
enum DifficultyLevel {
    Easy,
    Medium,
    Hard,
}

struct InterviewProcess {
    company: String,
    rounds: Vec<InterviewRound>,
    difficulty: DifficultyLevel,
}

impl InterviewProcess {
    fn new(company: String, rounds: Vec<InterviewRound>, 
           difficulty: DifficultyLevel) -> Self {
        InterviewProcess { company, rounds, difficulty }
    }

    fn get_total_time(&self) -> u32 {
        self.rounds.iter().map(|r| r.duration_minutes).sum()
    }

    fn get_preparation_hours(&self) -> u32 {
        match self.difficulty {
            DifficultyLevel::Easy => 20,
            DifficultyLevel::Medium => 40,
            DifficultyLevel::Hard => 60,
        }
    }

    fn get_round_names(&self) -> Vec<&str> {
        self.rounds.iter().map(|r| r.name.as_str()).collect()
    }
}

impl fmt::Display for InterviewProcess {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "{}: {} hours recommended\n", 
               self.company, self.get_preparation_hours())?;
        write!(f, "Total interview time: {} minutes\n", self.get_total_time())?;
        write!(f, "Rounds: {}\n", self.get_round_names().join(" → "))?;
        Ok(())
    }
}

fn main() {
