  }

  /**
   * Identify company domain from name
   * @returns {string} Domain type: 'streaming', 'search', 'social', 'payments', 'realtime'
   */
  identifyDomain() {
    const domainMap = {
      'netflix': 'streaming',
      'youtube': 'streaming',
      'disney': 'streaming',
      'google': 'search',
      'meta': 'social',
      'facebook': 'social',
      'tiktok': 'social',
      'stripe': 'payments',
      'square': 'payments',
      'uber': 'realtime',
      'lyft': 'realtime',
    };
    return domainMap[this.company.toLowerCase()] || 'generic';
  }

  /**
   * Get typical interview questions by domain
   */
  getDomainQuestions() {
    const questionsByDomain = {
      streaming: [
        'Design a video streaming service',
        'Handle 10M concurrent viewers with <2 second latency',
        'Adaptive bitrate algorithm',
        'CDN and edge caching strategy',
      ],
      search: [
        'Design Google search engine',
        'Building a distributed search index',
        'Ranking and relevance algorithms',
        'Web crawling at scale',
      ],
      social: [
        'Design Instagram feed',
        'Recommendation system for 1B items',
        'Real-time activity aggregation',
        'Handling massive write volume',
      ],
      payments: [
        'Design a payment processing system',
        'Transaction consistency and idempotency',
        'Handling payment failures and retries',
        'Fraud detection at scale',
      ],
      realtime: [
        'Design Uber ride matching',
        'Geospatial queries: find nearby drivers',
        'Real-time position tracking',
        'Matching algorithm optimization',
      ],
    };
    return questionsByDomain[this.identifyDomain()] || [];
  }

  /**
   * Extract question category from text
   */
  categorizeQuestion(text) {
    const lowerText = text.toLowerCase();
    if (lowerText.includes('design') || lowerText.includes('architecture')) {
      return 'system_design';
    }
    if (lowerText.includes('code') || lowerText.includes('implement')) {
      return 'coding';
    }
    if (lowerText.includes('behavior') || lowerText.includes('experience')) {
      return 'behavioral';
    }
    return 'other';
  }

  /**
   * Analyze interview question patterns from data
   */
  analyzePatterns(questions = []) {
    const analysis = {
      total: questions.length,
      byCategory: {},
      domainMatch: this.identifyDomain(),
    };

    questions.forEach((q) => {
      const cat = this.categorizeQuestion(q);
      analysis.byCategory[cat] = (analysis.byCategory[cat] || 0) + 1;
    });

    return analysis;
  }

  /**
   * Get tech stack for company
