    };
    return techStacks[this.company.toLowerCase()] || [];
  }

  /**
   * Generate interview prep checklist
   */
  generatePrepChecklist() {
    const domain = this.identifyDomain();
    const questions = this.getDomainQuestions();
    const techStack = this.getTechStack();

    return {
      company: this.company,
      domain,
      research: {
        mission: `What is ${this.company}'s core product?`,
        scale: 'What are their user count, QPS, and data volume?',
        techStack: `Tech stack: ${techStack.join(', ')}`,
        challenges: `What are their main technical challenges in ${domain}?`,
