#!/usr/bin/env python3
"""Scrape and analyze company interview patterns."""

import requests
from bs4 import BeautifulSoup
import json
from typing import List, Dict
import re

class CompanyInterviewResearcher:
    """Research company-specific interview patterns."""

    def __init__(self, company_name: str):
        self.company = company_name
        self.patterns = {}
        self.tech_stack = []
        self.domains = []

    def scrape_glassdoor_patterns(self, url: str) -> List[Dict]:
        """Extract interview question patterns from Glassdoor."""
        questions = []
        try:
            response = requests.get(url, timeout=10)
            soup = BeautifulSoup(response.content, 'html.parser')

            # Find interview sections
            for section in soup.find_all('div', class_='review'):
                question_text = section.get_text()

                # Categorize questions
                category = self._categorize_question(question_text)
                questions.append({
                    'text': question_text[:200],
                    'category': category,
                    'source': 'glassdoor'
                })
        except Exception as e:
            print(f"Error scraping: {e}")

        return questions

    def identify_domain(self) -> str:
        """Identify company domain from research.

        Returns:
            One of: 'streaming', 'search', 'payments', 'social', 'realtime'
        """
        company_domains = {
            'netflix': 'streaming',
            'disney+': 'streaming',
            'youtube': 'streaming',
            'google': 'search',
            'meta': 'social',
            'tiktok': 'social',
            'stripe': 'payments',
            'uber': 'realtime',
            'lyft': 'realtime',
        }
        return company_domains.get(self.company.lower(), 'generic')

    def get_domain_focus(self) -> Dict[str, List[str]]:
        """Get typical questions for company domain."""
        domain = self.identify_domain()

        domain_patterns = {
            'streaming': {
                'questions': [
                    'Design a video streaming service',
                    'Handle 10M concurrent viewers',
                    'How do you adapt bitrate?'
                ],
                'topics': ['CDN', 'caching', 'load-balancing', 'latency']
            },
            'search': {
                'questions': [
                    'Design Google search',
                    'Ranking and relevance at scale',
                    'Crawling the web efficiently'
                ],
                'topics': ['algorithms', 'indexing', 'ranking']
            },
            'social': {
                'questions': [
                    'Design a recommendation feed',
                    'Rank 1B items for a user',
                    'Handle feed generation at scale'
                ],
                'topics': ['recommendations', 'ml', 'real-time-aggregation']
            },
            'payments': {
                'questions': [
                    'Design a payment system',
                    'Handle transaction failures',
                    'Ensure ACID compliance at scale'
                ],
                'topics': ['transactions', 'idempotency', 'consistency']
            },
            'realtime': {
                'questions': [
                    'Design ride matching',
                    'Query nearby drivers efficiently',
                    'Real-time position tracking'
                ],
                'topics': ['geospatial', 'real-time', 'eventually-consistent']
            }
        }

        return domain_patterns.get(domain, {})

    def _categorize_question(self, question: str) -> str:
        """Categorize interview question type."""
        if 'design' in question.lower() or 'architecture' in question.lower():
            return 'system_design'
        elif 'code' in question.lower() or 'implement' in question.lower():
            return 'coding'
        elif 'behavior' in question.lower() or 'why' in question.lower():
            return 'behavioral'
        else:
            return 'other'

    def analyze_patterns(self, questions: List[Dict]) -> Dict:
        """Analyze interview question patterns."""
        if not questions:
            return {}

        categories = {}
        for q in questions:
            cat = q['category']
            categories[cat] = categories.get(cat, 0) + 1

        return {
            'total_questions': len(questions),
            'distribution': categories,
            'domain': self.identify_domain(),
            'expected_focus': self.get_domain_focus()
        }

    def generate_prep_plan(self) -> str:
        """Generate personalized interview prep plan."""
        domain_focus = self.get_domain_focus()

        plan = f"""
        Interview Prep Plan for {self.company}
        =========================================

        Domain: {self.identify_domain().upper()}

        Expected Questions:
        """

        for q in domain_focus.get('questions', []):
            plan += f"\n  - {q}"

        plan += "\n\nFocus Areas:"
        for topic in domain_focus.get('topics', []):
            plan += f"\n  - {topic}"

        return plan

# Usage
if __name__ == '__main__':
    researcher = CompanyInterviewResearcher('Netflix')
    print(researcher.generate_prep_plan())

    domain_info = researcher.get_domain_focus()
    print(f"\nDomain-specific questions: {len(domain_info.get('questions', []))}")

