}

#[derive(Clone, Debug)]
pub struct CompanyProfile {
    name: String,
    domain: CompanyDomain,
    tech_stack: Vec<String>,
    users: u64,
    qps: u64,
    core_challenge: String,
}

#[derive(Clone, Debug)]
pub struct InterviewQuestion {
    text: String,
    category: QuestionCategory,
    domain: CompanyDomain,
}

#[derive(Clone, Debug)]
pub enum QuestionCategory {
    SystemDesign,
    Coding,
    Behavioral,
}

pub struct CompanyInterviewAnalyzer {
    profiles: HashMap<String, CompanyProfile>,
}

impl CompanyInterviewAnalyzer {
    pub fn new() -> Self {
        let mut profiles = HashMap::new();

        // Netflix: massive scale streaming
        profiles.insert(
            "netflix".to_string(),
            CompanyProfile {
                name: "Netflix".to_string(),
                domain: CompanyDomain::Streaming,
                tech_stack: vec![
                    "Java".to_string(),
                    "Cassandra".to_string(),
                    "Kafka".to_string(),
                    "Redis".to_string(),
                ],
                users: 250_000_000,
                qps: 1_000_000,
                core_challenge: "Stream 4K video to 250M users with <2s latency".to_string(),
            },
        );

        // Google: search at scale
        profiles.insert(
            "google".to_string(),
            CompanyProfile {
                name: "Google".to_string(),
                domain: CompanyDomain::Search,
                tech_stack: vec![
                    "C++".to_string(),
                    "Java".to_string(),
                    "Bigtable".to_string(),
                ],
                users: 2_000_000_000,
                qps: 100_000_000,
                core_challenge: "Index and rank 100B web pages in <100ms".to_string(),
            },
        );

        // Stripe: payments with zero data loss
        profiles.insert(
            "stripe".to_string(),
            CompanyProfile {
                name: "Stripe".to_string(),
                domain: CompanyDomain::Payments,
                tech_stack: vec![
                    "Python".to_string(),
                    "PostgreSQL".to_string(),
                    "Redis".to_string(),
                ],
                users: 500_000,
                qps: 100_000,
                core_challenge: "Process billions in payments with zero data loss".to_string(),
            },
        );

        CompanyInterviewAnalyzer { profiles }
    }

    pub fn get_profile(&self, company: &str) -> Option<CompanyProfile> {
        self.profiles.get(&company.to_lowercase()).cloned()
    }

    pub fn get_typical_questions(&self, domain: &CompanyDomain) -> Vec<InterviewQuestion> {
        let questions = match domain {
            CompanyDomain::Streaming => vec![
                "Design a video streaming service",
                "Handle 10M concurrent viewers with <2s latency",
                "Implement adaptive bitrate algorithm",
                "Design CDN and edge caching strategy",
            ],
            CompanyDomain::Search => vec![
                "Design Google search engine",
                "Build distributed search index",
                "Ranking algorithm at scale",
                "Index 100B documents efficiently",
            ],
            CompanyDomain::Payments => vec![
                "Design payment processing system",
                "Ensure transaction consistency",
                "Handle transaction failures gracefully",
                "Implement idempotent APIs",
            ],
            CompanyDomain::Social => vec![
                "Design recommendation feed",
                "Rank 1B items for single user",
                "Real-time activity aggregation",
                "Handle massive write volume",
            ],
            CompanyDomain::RealTime => vec![
                "Design ride matching algorithm",
                "Query nearby drivers efficiently",
                "Real-time position tracking",
                "Optimize matching latency",
            ],
        };

        questions
            .into_iter()
            .map(|text| InterviewQuestion {
                text: text.to_string(),
                category: QuestionCategory::SystemDesign,
                domain: domain.clone(),
            })
            .collect()
    }

    pub fn domain_to_string(domain: &CompanyDomain) -> &'static str {
        match domain {
            CompanyDomain::Streaming => "Streaming",
            CompanyDomain::Search => "Search",
            CompanyDomain::Social => "Social",
            CompanyDomain::Payments => "Payments",
            CompanyDomain::RealTime => "Real-time",
        }
    }

    pub fn print_prep_plan(&self, company_name: &str) {
        if let Some(profile) = self.get_profile(company_name) {
            println!("\n=== Interview Prep for {} ===", profile.name);
            println!("Domain: {}", Self::domain_to_string(&profile.domain));
            println!("Core Challenge: {}", profile.core_challenge);
            println!("\nScale:");
            println!("  Users: {}", profile.users);
            println!("  QPS: {}", profile.qps);

            println!("\nTech Stack:");
            for tech in &profile.tech_stack {
                println!("  - {}", tech);
            }

            let questions = self.get_typical_questions(&profile.domain);
            println!("\nExpected Questions:");
            for q in questions {
                println!("  - {}", q.text);
            }

            println!("\nInterview Strategy:");
            println!("  1. Reference their actual architecture");
            println!("  2. Design for their scale constraints");
            println!("  3. Use their tech stack where applicable");
            println!("  4. Discuss trade-offs relevant to domain");
        } else {
            println!("Company profile not found: {}", company_name);
        }
    }
}

fn main() {
    let analyzer = CompanyInterviewAnalyzer::new();

    // Prepare for Netflix interview
    analyzer.print_prep_plan("netflix");

    // Prepare for Google interview
    analyzer.print_prep_plan("google");

    // Prepare for Stripe interview
    analyzer.print_prep_plan("stripe");
}

