# C++
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

// Research data structure
typedef struct {
    char company_name[256];
    char tech_stack[5][256];
    int tech_count;
    char blog_topics[5][512];
    int blog_count;
    char recent_initiatives[3][256];
    int initiative_count;
    char architecture[64];  // "microservices", "monolith", etc.
} CompanyResearch;

// Technical question structure
typedef struct {
    char question[1024];
    char why[512];
    char follow_up[512];
    char quality[32];  // "excellent", "good", "fair"
    int score;  // 1-10
} TechnicalQuestion;

/**
 * Rate the quality of a technical question (1-10)
 * Better questions:
 * - Reference specific research (I saw, I read)
 * - Ask about tradeoffs (why, vs, choice)
 * - Open-ended (not yes/no)
 * - Show systems thinking (scale, bottleneck, consistency)
 */
int rate_question_quality(const char *question) {
    int score = 0;
    char q_lower[1024];

    // Convert to lowercase for comparison
    strcpy(q_lower, question);
    for (int i = 0; q_lower[i]; i++) {
        if (q_lower[i] >= 'A' && q_lower[i] <= 'Z') {
            q_lower[i] = q_lower[i] - 'A' + 'a';
        }
    }

    // Check for specific research ("I saw", "I read")
    if (strstr(q_lower, "i saw") || strstr(q_lower, "i read") ||
        strstr(q_lower, "i noticed")) {
        score += 3;
    }

    // Check for tradeoff questions ("why", "vs", "choice")
    if (strstr(q_lower, "why") || strstr(q_lower, "vs") ||
        strstr(q_lower, "versus") || strstr(q_lower, "choice") ||
        strstr(q_lower, "alternative") || strstr(q_lower, "tradeoff")) {
        score += 2;
    }

    // Check for open-ended (not starting with Do, Is, Can, Have)
    if (strncmp(q_lower, "do ", 3) != 0 &&
        strncmp(q_lower, "is ", 3) != 0 &&
        strncmp(q_lower, "can ", 4) != 0 &&
        strncmp(q_lower, "have ", 5) != 0) {
        score += 2;
    }

    // Check for systems thinking
    if (strstr(q_lower, "scale") || strstr(q_lower, "bottleneck") ||
        strstr(q_lower, "consistency") || strstr(q_lower, "reliability") ||
        strstr(q_lower, "challenge")) {
        score += 3;
    }

    return score > 10 ? 10 : score;
}

/**
 * Generate smart technical questions based on company research
 */
int generate_technical_questions(CompanyResearch *research, 
                                TechnicalQuestion *questions,
                                int max_questions) {
    int count = 0;

    // Pattern 1: Reference blog topics about scaling/challenges
    for (int i = 0; i < research->blog_count && count < max_questions; i++) {
        if (strstr(research->blog_topics[i], "scaling") ||
            strstr(research->blog_topics[i], "scale") ||
            strstr(research->blog_topics[i], "performance")) {

            snprintf(
                questions[count].question, sizeof(questions[count].question),
                "I read your blog post about %s. What were the biggest "
                "bottlenecks you encountered, and how did you solve them?",
                research->blog_topics[i]
            );

            strcpy(questions[count].why,
                   "Shows you researched their blog, asks about real challenges");
            strcpy(questions[count].follow_up,
                   "How do you prevent similar bottlenecks in new features?");
            strcpy(questions[count].quality, "excellent");
            questions[count].score = rate_question_quality(questions[count].question);

            count++;
        }
    }

    // Pattern 2: Ask about tech stack choices
    if (research->tech_count > 0 && count < max_questions) {
        snprintf(
            questions[count].question, sizeof(questions[count].question),
            "What made you choose %s for this use case? What were the "
            "alternatives you considered, and what were the tradeoffs?",
            research->tech_stack[0]
        );

        strcpy(questions[count].why,
               "Shows systems thinking, asks about decision-making process");
        strcpy(questions[count].follow_up,
               "How do you handle cases where that choice isn't optimal?");
        strcpy(questions[count].quality, "excellent");
        questions[count].score = rate_question_quality(questions[count].question);

        count++;
    }

    // Pattern 3: Architecture-specific questions
    if (strcmp(research->architecture, "microservices") == 0 && count < max_questions) {
        strcpy(questions[count].question,
               "How do you handle distributed tracing and observability "
               "across your microservices? What challenges have you faced "
               "with service-to-service communication?");

        strcpy(questions[count].why,
               "Shows understanding of their architecture complexity");
        strcpy(questions[count].follow_up,
               "How do you handle consistency guarantees in a distributed system?");
        strcpy(questions[count].quality, "excellent");
        questions[count].score = rate_question_quality(questions[count].question);

        count++;
    }

    // Pattern 4: Reference recent initiatives
    for (int i = 0; i < research->initiative_count && count < max_questions; i++) {
        snprintf(
            questions[count].question, sizeof(questions[count].question),
            "I saw that you're %s. What are the biggest technical "
            "challenges you're facing in this initiative?",
            research->recent_initiatives[i]
        );

        strcpy(questions[count].why,
               "Shows you follow the company, asks about current real work");
        strcpy(questions[count].follow_up,
               "What's your timeline, and what's the biggest blocker?");
        strcpy(questions[count].quality, "excellent");
        questions[count].score = rate_question_quality(questions[count].question);

        count++;
    }

    return count;
}

int main() {
    // Example company research
    CompanyResearch research = {
        .company_name = "TechCorp",
        .tech_stack = {"Go", "PostgreSQL", "Kubernetes", "Kafka"},
        .tech_count = 4,
        .blog_topics = {
            "Scaling payment processing to 1M transactions/sec",
            "How we reduced p99 latency by 50%"
        },
        .blog_count = 2,
        .recent_initiatives = {
            "expanding to APAC with regional data centers",
            "migrating to event-driven architecture"
        },
        .initiative_count = 2,
        .architecture = "microservices"
    };

    // Generate questions
    TechnicalQuestion questions[10];
    int question_count = generate_technical_questions(
        &research, questions, 10
    );

    printf("Generated %d technical questions for %s\n\n",
           question_count, research.company_name);

    for (int i = 0; i < question_count; i++) {
        printf("Question %d:\n", i + 1);
        printf("  Q: %s\n", questions[i].question);
        printf("  Why: %s\n", questions[i].why);
        printf("  Quality: %s (Score: %d/10)\n",
               questions[i].quality, questions[i].score);
        printf("  Follow-up: %s\n\n", questions[i].follow_up);
    }

    return 0;
}


# Go
package main

import (
	"fmt"
	"strings"
)

// CompanyResearch represents researched information about a company
type CompanyResearch struct {
	Name              string
	TechStack         []string
	BlogTopics        []string
	RecentInitiatives []string
	Architecture      string
}

// TechnicalQuestion represents a well-crafted technical interview question
type TechnicalQuestion struct {
	Question  string
	Why       string
	FollowUp  string
	Quality   string
}

// GenerateTechnicalQuestions creates interview questions based on research
func GenerateTechnicalQuestions(research CompanyResearch) []TechnicalQuestion {
	var questions []TechnicalQuestion

	// Pattern 1: Reference blog posts about scaling
	for _, topic := range research.BlogTopics {
		if strings.Contains(strings.ToLower(topic), "scaling") ||
			strings.Contains(strings.ToLower(topic), "scale") {
			questions = append(questions, TechnicalQuestion{
				Question: fmt.Sprintf(
					"I read your blog post about %s. What were the biggest bottlenecks "+
					\"you encountered, and how did you solve them?\",
					topic,
				),
				Why:     "Shows you researched their work, asks about real challenges",
				FollowUp: "How do you handle [specific technical aspect] at that scale?",
				Quality: "excellent",
			})
		}
	}

	// Pattern 2: Ask about tech stack choices and tradeoffs
	for _, tech := range research.TechStack {
		if len(tech) > 0 {
			questions = append(questions, TechnicalQuestion{
				Question: fmt.Sprintf(
					"What made you choose %s for this use case? What were the "+
					\"alternatives you considered, and what were the tradeoffs?\",
					tech,
				),
				Why:     "Shows systems thinking, asks about decision-making process",
				FollowUp: "How do you handle cases where that choice isn't optimal?",
				Quality: "excellent",
			})
			break // Just one for brevity
		}
	}

	// Pattern 3: Ask about architecture challenges
	if research.Architecture == "microservices" {
		questions = append(questions, TechnicalQuestion{
			Question: "How do you handle distributed tracing and observability across " +
				"your microservices? What challenges have you faced with service-to-service " +
				"communication?",
			Why:     "Shows understanding of their architecture and its complexity",
			FollowUp: "How do you handle consistency guarantees in a distributed system?",
			Quality: "excellent",
		})
	}

	// Pattern 4: Reference recent news or initiatives
	for _, initiative := range research.RecentInitiatives {
		questions = append(questions, TechnicalQuestion{
			Question: fmt.Sprintf(
				"I saw that you're %s. What are the biggest technical challenges "+
				\"you're currently facing in this initiative?\",
				initiative,
			),
			Why:     "Shows you follow the company, asks about current real work",
			FollowUp: "What's your timeline, and what's blocking progress?",
			Quality: "excellent",
		})
	}

	return questions
}

// RateQuestionQuality scores how good a question is (1-10)
func RateQuestionQuality(question string) int {
	score := 0
	q := strings.ToLower(question)

	// Shows research (specific reference)
	if strings.Contains(q, "i saw") || strings.Contains(q, "i read") ||
		strings.Contains(q, "i noticed") || strings.Contains(q, "specific") {
		score += 3
	}

	// Asks about tradeoffs
	if strings.Contains(q, "why") || strings.Contains(q, "versus") ||
		strings.Contains(q, "vs") || strings.Contains(q, "choice") ||
		strings.Contains(q, "alternative") || strings.Contains(q, "tradeoff") {
		score += 2
	}

	// Open-ended (not yes/no)
	if !strings.HasPrefix(q, "do ") && !strings.HasPrefix(q, "is ") &&
		!strings.HasPrefix(q, "can ") && !strings.HasPrefix(q, "have ") {
		score += 2
	}

	// Shows systems thinking
	if strings.Contains(q, "scale") || strings.Contains(q, "bottleneck") ||
		strings.Contains(q, "challenge") || strings.Contains(q, "consistency") ||
		strings.Contains(q, "reliability") || strings.Contains(q, "handle") {
		score += 3
	}

	if score > 10 {
		score = 10
	}
	return score
}

func main() {
	// Example company research
	research := CompanyResearch{
		Name: "TechCorp",
		TechStack: []string{"Go", "PostgreSQL", "Kubernetes", "Kafka"},
		BlogTopics: []string{
			"Scaling payment processing to 1M transactions/sec",
			"How we reduced p99 latency by 50%",
		},
		RecentInitiatives: []string{
			"expanding to APAC with regional data centers",
			"migrating to event-driven architecture",
		},
		Architecture: "microservices",
	}

	// Generate questions
	questions := GenerateTechnicalQuestions(research)

	fmt.Printf("Generated %d technical questions for %s\n\n", len(questions), research.Name)

	for i, q := range questions {
		fmt.Printf("Question %d:\n", i+1)
		fmt.Printf("  Q: %s\n", q.Question)
		fmt.Printf("  Why: %s\n", q.Why)
		fmt.Printf("  Quality: %s (Score: %d/10)\n", q.Quality, RateQuestionQuality(q.Question))
		fmt.Printf("  Follow-up: %s\n\n", q.FollowUp)
	}
}


