      question: `I saw that you're ${news.initiative}. ` +
                "What are the biggest technical challenges you're facing in this transition?",
      why: "Shows you follow the company, asks about real current work",
      quality: "excellent"
    });
  }

  return questions;
}

/**
 * Rate the quality of a technical question
 */
function rateQuestionQuality(question) {
  let score = 0;
  const indicators = {
    hasSpecificReference: /I (saw|read|noticed|remember)/.test(question),
    asksAboutTradeoffs: /(why|versus|vs|over|choice|alternative|tradeoff)/.test(question),
    opensEnded: !question.match(/^(Do|Is|Can|Have)/),
    showsSystemsThinking: /(scale|bottleneck|consistency|reliability|challenge|handle)/.test(question),
    referencesResearch: /(blog|announced|published|github)/.test(question)
  };

  if (indicators.hasSpecificReference) score += 2;
  if (indicators.asksAboutTradeoffs) score += 2;
  if (indicators.opensEnded) score += 1;
  if (indicators.showsSystemsThinking) score += 2;
  if (indicators.referencesResearch) score += 3;

  return {
    score: Math.min(score, 10),
    indicators,
    feedback: score >= 8 ? "Excellent question!" : 
              score >= 5 ? "Good question" : 
              "Could be more specific/deeper"
  };
}

/**
 * Example usage
 */
const companyResearch = {
