        "recent_initiatives": [],
        "technical_questions": []
    }

    return company_info

def identify_tech_challenges(tech_stack: List[str]) -> List[str]:
    """
    Based on tech stack, identify potential technical challenges.
    """
    challenges = []

    # Example: If using microservices
    if any('microservice' in tech.lower() for tech in tech_stack):
        challenges.extend([
            "How do you handle distributed tracing?",
            "How do you manage service-to-service communication?",
            "How do you handle consistency across services?"
        ])

    # Example: If using Kafka or event streaming
    if any('kafka' in tech.lower() or 'event' in tech.lower() for tech in tech_stack):
        challenges.extend([
            "How do you handle ordering guarantees?",
            "How do you manage backpressure?",
            "How do you ensure exactly-once processing?"
        ])

    # Example: If using Kubernetes
    if any('kubernetes' in tech.lower() or 'k8s' in tech.lower() for tech in tech_stack):
        challenges.extend([
            "How do you handle state management in containers?",
            "How do you manage multi-region deployments?",
            "What's your approach to resource limits and autoscaling?"
        ])

    return challenges

def generate_technical_questions(company_data: Dict) -> List[str]:
    """
    Generate tailored technical questions based on company research.
    """
    questions = []

    # Reference specific blog posts
    if company_data['blog_topics']:
        blog = company_data['blog_topics'][0]
        if 'scaling' in blog.lower():
            questions.append(
                f"I read your blog post about scaling {blog} - "
                "what were the biggest bottlenecks you encountered?"
            )

    # Ask about architecture decisions
    if company_data['tech_stack']:
        tech = company_data['tech_stack'][0]
        questions.append(
            f"What made you choose {tech} for this use case? "
            "What were the alternatives you considered?"
        )

    # Ask about recent initiatives
    if company_data['recent_initiatives']:
        init = company_data['recent_initiatives'][0]
        questions.append(
            f"I saw you're working on {init} - "
            "what are the biggest technical challenges you're facing?"
        )

    return questions

def score_question_quality(question: str) -> int:
    """
    Score a technical question (1-10) based on quality indicators.
    """
    score = 0

    # Shows research (specific reference)
    if any(word in question for word in ['I saw', 'I read', 'noticed', 'specific']):
        score += 3

    # Asks about tradeoffs
    if any(word in question for word in ['why', 'vs', 'choice', 'alternative', 'tradeoff']):
        score += 2

    # Open-ended (not yes/no)
    if question.endswith('?') and not question.startswith(('Do', 'Is', 'Can')):
        score += 2

    # Shows systems thinking
    if any(word in question for word in ['scale', 'challenge', 'bottleneck', 'consistency', 'reliability']):
        score += 3

    return min(score, 10)

