# Rust
//! Technical Interview Question Generator and Evaluator
//! Research a company's tech stack and generate smart questions

use std::collections::HashMap;

#[derive(Debug, Clone)]
pub struct CompanyResearch {
    pub name: String,
    pub tech_stack: Vec<String>,
    pub blog_topics: Vec<String>,
    pub recent_initiatives: Vec<String>,
    pub architecture: String,
}

#[derive(Debug, Clone)]
pub struct TechnicalQuestion {
    pub question: String,
    pub why: String,
    pub follow_up: String,
    pub quality: String,
}

/// Generates smart technical questions based on company research
pub fn generate_technical_questions(research: &CompanyResearch) -> Vec<TechnicalQuestion> {
    let mut questions = Vec::new();

    // Pattern 1: Reference blog posts about scaling/challenges
    for topic in &research.blog_topics {
        if topic.to_lowercase().contains("scaling")
            || topic.to_lowercase().contains("scale")
            || topic.to_lowercase().contains("performance")
        {
            questions.push(TechnicalQuestion {
                question: format!(
                    "I read your blog post about {}. What were the biggest bottlenecks \
                    you encountered, and how did you solve them?",
                    topic
                ),
                why: "Shows you researched their technical blog, asks about real challenges"
                    .to_string(),
                follow_up: "How do you prevent similar bottlenecks in new features?".to_string(),
                quality: "excellent".to_string(),
            });
        }
    }

    // Pattern 2: Ask about tech stack choices and tradeoffs
    if let Some(primary_tech) = research.tech_stack.first() {
        questions.push(TechnicalQuestion {
            question: format!(
                "What made you choose {} for your primary infrastructure? \
                What were the alternatives, and what were the key tradeoffs?",
                primary_tech
            ),
            why: "Shows systems thinking, asks about architectural decisions".to_string(),
            follow_up: "How do you handle cases where that choice isn't optimal?" .to_string(),
            quality: "excellent".to_string(),
        });
    }

    // Pattern 3: Address architecture-specific challenges
    match research.architecture.as_str() {
        "microservices" => {
            questions.push(TechnicalQuestion {
                question: "How do you handle distributed tracing and observability \
                    across your microservices? What's your approach to service-to-service \
                    consistency?"
                    .to_string(),
                why: "Shows understanding of their architecture complexity".to_string(),
                follow_up: "How do you handle cascading failures?".to_string(),
                quality: "excellent".to_string(),
            });
        }
        "monolith" => {
            questions.push(TechnicalQuestion {
                question: "How do you handle scaling a large monolith? \
                    Are you planning to move toward microservices?"
                    .to_string(),
                why: "Shows you understand their architecture challenges".to_string(),
                follow_up: "What's holding you back from splitting services?" .to_string(),
                quality: "good".to_string(),
            });
        }
        _ => {}
    }

    // Pattern 4: Reference recent news or initiatives
    for initiative in &research.recent_initiatives {
        questions.push(TechnicalQuestion {
            question: format!(
                "I saw you're {}. What are the biggest technical \
                challenges you're facing in this initiative?",
                initiative
            ),
            why: "Shows you follow the company news, asks about current work".to_string(),
            follow_up: "What's your timeline, and what's the biggest blocker?".to_string(),
            quality: "excellent".to_string(),
        });
    }

    questions
}

/// Rates the quality of a technical question on a 1-10 scale
pub fn rate_question_quality(question: &str) -> (usize, HashMap<String, bool>) {
    let q_lower = question.to_lowercase();
    let mut score = 0;
    let mut indicators = HashMap::new();

    // Indicator 1: Shows specific research
    let has_specific_reference = q_lower.contains("i saw")
        || q_lower.contains("i read")
        || q_lower.contains("i noticed")
        || q_lower.contains("your blog");
    indicators.insert(
        "specific_reference".to_string(),
        has_specific_reference,
    );
    if has_specific_reference {
        score += 3;
    }

    // Indicator 2: Asks about tradeoffs
    let asks_tradeoffs = q_lower.contains("why")
        || q_lower.contains("versus")
        || q_lower.contains("vs")
        || q_lower.contains("alternative")
        || q_lower.contains("tradeoff");
    indicators.insert("asks_tradeoffs".to_string(), asks_tradeoffs);
    if asks_tradeoffs {
        score += 2;
    }

    // Indicator 3: Open-ended question
    let is_open_ended = !q_lower.starts_with("do ")
        && !q_lower.starts_with("is ")
        && !q_lower.starts_with("can ")
        && !q_lower.starts_with("have ");
    indicators.insert("open_ended".to_string(), is_open_ended);
    if is_open_ended {
        score += 2;
    }

    // Indicator 4: Shows systems thinking
    let shows_systems_thinking = q_lower.contains("scale")
        || q_lower.contains("bottleneck")
        || q_lower.contains("consistency")
        || q_lower.contains("reliability")
        || q_lower.contains("challenge")
        || q_lower.contains("handle");
    indicators.insert("systems_thinking".to_string(), shows_systems_thinking);
    if shows_systems_thinking {
        score += 3;
    }

    (score.min(10), indicators)
}

fn main() {
    // Example company research
    let research = CompanyResearch {
        name: "TechCorp".to_string(),
        tech_stack: vec![
            "Rust".to_string(),
            "PostgreSQL".to_string(),
            "Kubernetes".to_string(),
        ],
        blog_topics: vec![
            "Scaling our API to 1M requests/second".to_string(),
            "How we reduced p99 latency by 70%".to_string(),
        ],
        recent_initiatives: vec!["launching in 5 new markets".to_string()],
        architecture: "microservices".to_string(),
    };

    // Generate questions
    let questions = generate_technical_questions(&research);

    println!("Generated {} technical questions for {}\n", questions.len(), research.name);

    for (i, q) in questions.iter().enumerate() {
        println!("Question {}:", i + 1);
        println!("  Q: {}", q.question);
        println!("  Why: {}", q.why);

        let (score, indicators) = rate_question_quality(&q.question);
        println!("  Quality: {} (Score: {}/10)", q.quality, score);
        println!("  Indicators: {:?}", indicators);
        println!("  Follow-up: {}\n", q.follow_up);
    }
}

