package main

import (
	"fmt"
	"strings"
)

type ResearchCategory string

const (
	Acquisition ResearchCategory = "acquisition"
	Expansion   ResearchCategory = "expansion"
)

type CompanyResearch struct {
	CompanyName             string
	RecentMoves             []string
	CompetitivePosition     string
	EngineeringChallenges   []string
}

type QuestionAnalysis struct {
	Move                   string
	Category               ResearchCategory
	StrategicAngles        []string
	SuggestedQuestions     []string
}

func AnalyzeCompanyMove(move string, category ResearchCategory) QuestionAnalysis {
	analysis := QuestionAnalysis{
		Move:     move,
		Category: category,
	}

	switch category {
	case Acquisition:
		analysis.StrategicAngles = []string{
			"How will acquisition integrate into current architecture?",
			"What technical capabilities were you missing before?",
		}
		analysis.SuggestedQuestions = []string{
			"I saw you acquired [company] — how is that impacting your roadmap for [product]?",
			"How are you thinking about integrating [acquired company]'s tech with your existing stack?",
		}
	case Expansion:
		analysis.StrategicAngles = []string{
			"What new technical challenges does this market create?",
			"How will you adapt your product?",
		}
		analysis.SuggestedQuestions = []string{
			"Your expansion to [market] seems significant — what are the technical challenges you're facing?",
			"How are you scaling infrastructure to support the [market] expansion?",
		}
	}

	return analysis
}

func BuildStrategicQuestions(research CompanyResearch) []string {
	questionMap := make(map[string]bool)
	for _, move := range research.RecentMoves {
		var category ResearchCategory
		lowerMove := strings.ToLower(move)

		if strings.Contains(lowerMove, "acquire") {
			category = Acquisition
		} else if strings.Contains(lowerMove, "expand") {
			category = Expansion
		} else {
			continue
		}

		analysis := AnalyzeCompanyMove(move, category)
		for _, q := range analysis.SuggestedQuestions {
			questionMap[q] = true
		}
	}

	var questions []string
	for q := range questionMap {
		questions = append(questions, q)
	}
	return questions
}

func main() {
	research := CompanyResearch{
		CompanyName: "TechCorp",
		RecentMoves: []string{"Acquired DataFlow", "Expanded to Europe"},
		CompetitivePosition: "AI-first platform",
	}
	questions := BuildStrategicQuestions(research)
	fmt.Printf("Generated %d strategic questions\n", len(questions))
	for _, q := range questions {
		fmt.Printf("- %s\n", q)
	}
}

