      assessment.score -= 20;
    }
  });
  assessment.isStrategic = assessment.score >= 70;
  return assessment;
}

if (typeof module !== 'undefined' && module.exports) {
  module.exports = { ResearchCategory, analyzeCompanyMove, buildStrategicQuestions, assessQuestionQuality };
}

