#!/usr/bin/env python3
"""Research and prepare strategic interview questions."""

import json
from dataclasses import dataclass
from typing import List
from enum import Enum

class ResearchCategory(Enum):
    ACQUISITION = "acquisition"
    EXPANSION = "expansion"
    PARTNERSHIP = "partnership"
    FUNDING = "funding"
    PRODUCT = "product"

@dataclass
class CompanyResearch:
    company_name: str
    recent_moves: List[str]
    competitive_position: str
    engineering_challenges: List[str]
    culture_signals: List[str]
    strategic_questions: List[str]

def analyze_company_move(move: str, category: ResearchCategory) -> dict:
    """
    Analyze a company move and suggest strategic angles.
    """
    analysis = {
        "move": move,
        "category": category.value,
        "strategic_angles": [],
        "suggested_questions": []
    }

    if category == ResearchCategory.ACQUISITION:
        analysis["strategic_angles"] = [
            "How will acquisition integrate into current architecture?",
            "What technical capabilities were you missing before?",
            "How does this change the roadmap?"
        ]
        analysis["suggested_questions"] = [
            "I saw you acquired [company] — how is that impacting your roadmap for [product]?",
            "How are you thinking about integrating [acquired company]'s tech with your existing stack?"
        ]

    elif category == ResearchCategory.EXPANSION:
        analysis["strategic_angles"] = [
            "What new technical challenges does this market create?",
            "How will you adapt your product?",
            "What's your localization/scale strategy?"
        ]
        analysis["suggested_questions"] = [
            "Your expansion to [market] seems significant — what are the technical challenges you're facing?",
            "How are you scaling infrastructure to support the [market] expansion?"
        ]

    return analysis

def build_strategic_questions(research: CompanyResearch) -> List[str]:
    """
    Build a list of strategic questions from research.
    """
    questions = []
    for move in research.recent_moves:
        if "acquire" in move.lower():
            analysis = analyze_company_move(move, ResearchCategory.ACQUISITION)
        elif "expand" in move.lower():
            analysis = analyze_company_move(move, ResearchCategory.EXPANSION)
        else:
            continue
        questions.extend(analysis["suggested_questions"])
    return list(set(questions))

def assess_question_quality(question: str) -> dict:
    """
    Assess whether a question is strategic and appropriate.
    """
    red_flags = ["why did you", "aren't you", "what's your", "tell me about"]
    assessment = {"question": question, "is_strategic": True, "red_flags": [], "score": 100}

    lower_q = question.lower()
    for flag in red_flags:
        if flag in lower_q:
            assessment["red_flags"].append(flag)
            assessment["score"] -= 20

    assessment["is_strategic"] = assessment["score"] >= 70
    return assessment

