    recent_moves: Vec<String>,
    competitive_position: Option<String>,
    engineering_challenges: Vec<String>,
}

impl QuestionAnalysis {
    fn new(move_name: String, category: ResearchCategory) -> Self {
        let (strategic_angles, suggested_questions) = match category {
            ResearchCategory::Acquisition => (
                vec![
                    "How will acquisition integrate into current architecture?".to_string(),
                    "What technical capabilities were you missing before?".to_string(),
                ],
                vec![
                    "I saw you acquired [company] — how is that impacting your roadmap for [product]?"
                        .to_string(),
                    "How are you thinking about integrating [acquired company]'s tech with your stack?"
                        .to_string(),
                ],
            ),
            ResearchCategory::Expansion => (
                vec![
                    "What new technical challenges does this market create?".to_string(),
                    "How will you adapt your product?".to_string(),
                ],
                vec![
                    "Your expansion to [market] seems significant — what technical challenges are you facing?"
                        .to_string(),
                    "How are you scaling infrastructure to support the [market] expansion?".to_string(),
                ],
            ),
        };
        Self {
            move_name,
            category,
            strategic_angles,
            suggested_questions,
        }
    }
}

impl CompanyResearch {
    fn build_strategic_questions(&self) -> Vec<String> {
        let mut questions = HashSet::new();
        for move_name in &self.recent_moves {
            let lower = move_name.to_lowercase();
            let category = if lower.contains("acquire") {
                Some(ResearchCategory::Acquisition)
            } else if lower.contains("expand") {
                Some(ResearchCategory::Expansion)
            } else {
                None
            };
