package main

import (
	"context"
	"fmt"
	"log/slog"
	"math/rand"
	"net/http"
	"os"
	"time"

	"github.com/google/uuid"
	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promhttp"
)

var (
	// Metrics
	httpRequestsTotal = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "http_requests_total",
			Help: "Total HTTP requests",
		},
		[]string{"method", "endpoint", "status"},
	)
	httpRequestDuration = prometheus.NewHistogramVec(
		prometheus.HistogramOpts{
			Name: "http_request_duration_seconds",
			Help: "Request latency",
			Buckets: []float64{0.1, 0.5, 1.0, 2.0},
		},
		[]string{"method", "endpoint"},
	)
	dbConnectionsActive = prometheus.NewGauge(
		prometheus.GaugeOpts{
			Name: "db_connections_active",
			Help: "Active DB connections",
		},
	)
)

func init() {
	prometheus.MustRegister(httpRequestsTotal, httpRequestDuration, dbConnectionsActive)
}

// Context key for trace ID
type ctxKey string

const traceIDKey ctxKey = "trace_id"

// Structured logging with trace ID
func logWithTrace(ctx context.Context, level string, msg string, args ...interface{}) {
	traceID, _ := ctx.Value(traceIDKey).(string)
	attrs := []slog.Attr{
		slog.String("trace_id", traceID),
	}

	logger := slog.Default().With(attrs...)
	switch level {
	case "ERROR":
		logger.Error(msg, args...)
	case "WARN":
		logger.Warn(msg, args...)
	default:
		logger.Info(msg, args...)
	}
}

// Middleware to add trace ID and measure latency
func metricsMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// Add trace ID
		traceID := r.Header.Get("X-Trace-ID")
		if traceID == "" {
			traceID = uuid.New().String()
		}
		w.Header().Set("X-Trace-ID", traceID)

		ctx := context.WithValue(r.Context(), traceIDKey, traceID)
		r = r.WithContext(ctx)

		// Measure request
		start := time.Now()
		logWithTrace(ctx, "INFO", "request started", "method", r.Method, "path", r.URL.Path)

		// Wrap response writer to capture status code
		srw := &statusResponseWriter{ResponseWriter: w, statusCode: http.StatusOK}

		next.ServeHTTP(srw, r)

		duration := time.Since(start).Seconds()
		httpRequestsTotal.WithLabelValues(r.Method, r.URL.Path, fmt.Sprintf("%d", srw.statusCode)).Inc()
		httpRequestDuration.WithLabelValues(r.Method, r.URL.Path).Observe(duration)

		logWithTrace(ctx, "INFO", "request completed",
			"status", srw.statusCode,
			"duration_ms", fmt.Sprintf("%.0f", duration*1000))
	})
}

type statusResponseWriter struct {
	http.ResponseWriter
	statusCode int
}

func (srw *statusResponseWriter) WriteHeader(code int) {
	srw.statusCode = code
	srw.ResponseWriter.WriteHeader(code)
}

// Checkout endpoint with distributed tracing
func handleCheckout(w http.ResponseWriter, r *http.Request) {
	ctx := r.Context()
	logWithTrace(ctx, "INFO", "checkout started")

	// Simulate DB access
	dbConnectionsActive.Inc()
	defer dbConnectionsActive.Dec()

	// Simulate latency
	latency := time.Duration(100+rand.Intn(200)) * time.Millisecond
	time.Sleep(latency)
	logWithTrace(ctx, "INFO", "db query completed", "latency_ms", latency.Milliseconds())

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusOK)
	fmt.Fprintf(w, `{"status": "success", "trace_id": "%s"}\n`, ctx.Value(traceIDKey))
}

func handleHealth(w http.ResponseWriter, r *http.Request) {
	w.WriteHeader(http.StatusOK)
	fmt.Fprint(w, "OK")
}

func main() {
	// Setup structured logging
	slog.SetDefault(slog.New(
		slog.NewJSONHandler(os.Stdout, nil),
	))

	mux := http.NewServeMux()

	// Prometheus metrics endpoint
	mux.Handle("/metrics", promhttp.Handler())

	// Application endpoints with middleware
	mux.HandleFunc("/health", handleHealth)

	checkoutHandler := http.HandlerFunc(handleCheckout)
	mux.Handle("/checkout", metricsMiddleware(checkoutHandler))

	slog.Info("server starting", "port", "8080")
	if err := http.ListenAndServe(":8080", mux); err != nil {
		slog.Error("server error", "err", err)
	}
}

