import json
import os
import logging
from datetime import datetime
import boto3

logger = logging.getLogger()
logger.setLevel(logging.INFO)

# Global connection (reused across warm invocations)
db_connection = None
s3_client = boto3.client('s3')
secrets_client = boto3.client('secretsmanager')

def get_db_connection():
    """Lazy-load database connection to reduce cold start time."""
    global db_connection
    if db_connection is None:
        import psycopg2
        db_host = os.environ['DB_HOST']
        db_name = os.environ['DB_NAME']
        db_user = os.environ['DB_USER']

        secret = secrets_client.get_secret_value(SecretId='prod/db-password')
        db_password = json.loads(secret['SecretString'])['password']

        db_connection = psycopg2.connect(
            host=db_host,
            database=db_name,
            user=db_user,
            password=db_password,
            connect_timeout=5
        )
    return db_connection

def process_order(order_id, user_id, total):
    """Process a customer order."""
    conn = get_db_connection()
    cursor = conn.cursor()

    try:
        cursor.execute("BEGIN")
        cursor.execute(
            "INSERT INTO orders (id, user_id, total, created_at) VALUES (%s, %s, %s, %s)",
            (order_id, user_id, total, datetime.utcnow())
        )
        cursor.execute(
            "UPDATE users SET balance = balance - %s WHERE id = %s",
            (total, user_id)
        )
        conn.commit()
        logger.info(f"Order {order_id} processed successfully")
        return {'status': 'success', 'order_id': order_id}
    except Exception as e:
        conn.rollback()
        logger.error(f"Failed to process order {order_id}: {str(e)}")
        raise

def handler(event, context):
    logger.info(f"Invocation ID: {context.invocation_id}")
    logger.info(f"Event: {json.dumps(event)}")

    try:
        records = event.get('Records', [])
        results = []

        for record in records:
            body = json.loads(record['body'])
            result = process_order(body['order_id'], body['user_id'], body['total'])
            results.append(result)

        return {'statusCode': 200, 'body': json.dumps({'processed': len(results), 'results': results})}
    except Exception as e:
        logger.exception(f"Unhandled error: {str(e)}")
        raise

# JavaScript
const AWS = require('aws-sdk');
const s3 = new AWS.S3();
const dynamodb = new AWS.DynamoDB.DocumentClient();

let dbPool = null;

async function getDbPool() {
  if (dbPool === null) {
    const { Pool } = require('pg');
    dbPool = new Pool({
      host: process.env.DB_HOST,
      database: process.env.DB_NAME,
      user: process.env.DB_USER,
      password: process.env.DB_PASSWORD,
      max: 1,
      idleTimeoutMillis: 30000
    });
  }
  return dbPool;
}

async function processOrderAsync(orderId, userId, total) {
  const pool = await getDbPool();
  const client = await pool.connect();

  try {
    await client.query('BEGIN');
    await client.query(
      'INSERT INTO orders (id, user_id, total, created_at) VALUES ($1, $2, $3, $4)',
      [orderId, userId, total, new Date()]
    );
    await client.query(
      'UPDATE users SET balance = balance - $1 WHERE id = $2',
      [total, userId]
    );
    await client.query('COMMIT');
    console.log(`Order ${orderId} processed successfully`);
    return { status: 'success', orderId };
  } catch (error) {
    await client.query('ROLLBACK');
    console.error(`Failed to process order ${orderId}:`, error);
    throw error;
  } finally {
    client.release();
  }
}

exports.sqsHandler = async (event, context) => {
  console.log(`Invocation ID: ${context.awsRequestId}`);

  try {
    const records = event.Records || [];
    const results = [];

    for (const record of records) {
      const body = JSON.parse(record.body);
      const result = await processOrderAsync(body.order_id, body.user_id, body.total);
      results.push(result);
    }

    return { statusCode: 200, body: JSON.stringify({ processed: results.length, results }) };
  } catch (error) {
    console.error('Unhandled error:', error);
    throw error;
  }
};

