	UserID  string  `json:"user_id"`
	Total   float64 `json:"total"`
}

func processOrder(ctx context.Context, orderId, userId string, total float64) (map[string]interface{}, error) {
	slog.InfoContext(ctx, "Processing order", "order_id", orderId, "user_id", userId)

	result := map[string]interface{}{
		"status":   "success",
		"order_id": orderId,
	}
	return result, nil
}

func handleSQS(ctx context.Context, event map[string]interface{}) (interface{}, error) {
	slog.InfoContext(ctx, "Processing SQS event")

	records := event["Records"].([]interface{})
	var results []interface{}

	for _, record := range records {
		var payload OrderPayload
		data := record.(map[string]interface{})["body"].(string)

		json.Unmarshal([]byte(data), &payload)
		result, _ := processOrder(ctx, payload.OrderID, payload.UserID, payload.Total)
		results = append(results, result)
	}

	return map[string]interface{}{"processed": len(results), "results": results}, nil
}

func main() {
	lambda.Start(handleSQS)
}

