use aws_sdk_dynamodb::types::AttributeValue;
use lambda::{handler_fn, Context};
use serde::{Deserialize, Serialize};

#[derive(Deserialize)]
struct OrderPayload {
    order_id: String,
    user_id: String,
    total: f64,
}

#[derive(Serialize)]
struct OrderResponse {
    status: String,
    order_id: String,
}

async fn process_order(
    order_id: &str,
    user_id: &str,
    total: f64,
) -> Result<OrderResponse, Box<dyn std::error::Error>> {
    println!("Processing order {} for user {}", order_id, user_id);

    Ok(OrderResponse {
        status: "success".to_string(),
        order_id: order_id.to_string(),
    })
}

async fn handle_sqs(
    event: serde_json::Value,
) -> Result<serde_json::Value, lambda::error::FunctionError> {
    let records = event["Records"].as_array().unwrap_or(&vec![]);
    let mut results = Vec::new();

    for record in records {
        let body: OrderPayload = serde_json::from_str(&record["body"].as_str().unwrap())?;
        let response = process_order(&body.order_id, &body.user_id, body.total)
            .await
            .map_err(|e| lambda::error::FunctionError::new(e))?;
        results.push(response);
    }

    Ok(serde_json::json!({"processed": results.len(), "results": results}))
}

#[tokio::main]
async fn main() -> Result<(), lambda::error::FunctionError> {
    lambda::run(handler_fn(handle_sqs)).await
}

