int main() {
    // Initialize connection
    SF_STATUS status;
    SF_CONNECT *conn = snowflake_create_connect();

    snowflake_set_attribute(conn, SF_CON_ACCOUNT, "xy12345.us-east-1");
    snowflake_set_attribute(conn, SF_CON_USER, "user@company.com");
    snowflake_set_attribute(conn, SF_CON_PASSWORD, "password");
    snowflake_set_attribute(conn, SF_CON_WAREHOUSE, "compute_wh");
    snowflake_set_attribute(conn, SF_CON_DATABASE, "raw_db");

    status = snowflake_connect(conn);
    if (status != SF_STATUS_SUCCESS) {
        fprintf(stderr, "Connection failed\n");
        return 1;
    }

    // Execute COPY
    SF_STMT *stmt = snowflake_prepare(
        conn,
        "COPY INTO users FROM 's3://my-bucket/users/'"
        "CREDENTIALS = (aws_key_id = '...' aws_secret_key = '...')"
        "FILE_FORMAT = (TYPE = PARQUET)",
        0
    );

    status = snowflake_execute(stmt);
    if (status != SF_STATUS_SUCCESS) {
        fprintf(stderr, "COPY failed\n");
        return 1;
    }

    // MERGE
    stmt = snowflake_prepare(
        conn,
        "MERGE INTO users t USING staging_users s ON t.user_id = s.user_id "
        "WHEN MATCHED THEN UPDATE SET t.email = s.email "
        "WHEN NOT MATCHED THEN INSERT VALUES (s.user_id, s.name, s.email)",
        0
    );

    status = snowflake_execute(stmt);
    printf("Migration complete\n");

    snowflake_stmt_close(stmt);
    snowflake_disconnect(conn);
    return 0;
}

