# Python — Snowflake ETL Pipeline
import snowflake.connector

class SnowflakeETL:
    def __init__(self, account, user, password, warehouse, database):
        self.conn = snowflake.connector.connect(
            account=account, user=user, password=password,
            warehouse=warehouse, database=database
        )
        self.cursor = self.conn.cursor()

    def load_from_stage(self, stage_name, table_name, file_format='PARQUET'):
        query = f"""
        COPY INTO {table_name} FROM @{stage_name}/
        FILE_FORMAT = (TYPE = '{file_format}')
        ON_ERROR = CONTINUE PURGE = TRUE;
        """
        self.cursor.execute(query)
        return self.cursor.fetchall()

    def create_bronze_table(self, source_table, bronze_table):
        query = f"""
        CREATE OR REPLACE TABLE {bronze_table} AS
        SELECT *, CURRENT_TIMESTAMP as load_timestamp
        FROM {source_table};
        """
        self.cursor.execute(query)

    def stream_changes(self, stream_name):
        self.cursor.execute(f"SELECT * FROM {stream_name}")
        return self.cursor.fetchall()

    def resume_task(self, task_name):
        self.cursor.execute(f"ALTER TASK {task_name} RESUME;")

    def close(self):
        self.cursor.close()
        self.conn.close()

etl = SnowflakeETL('xy12345.us-east-1', 'user', 'pass', 'COMPUTE_WH', 'RAW_DATA')
