# JavaScript
// Big O Complexity Analysis Examples in JavaScript

// O(1) - Constant: Direct access
function getFirstElement(arr) {
  return arr[0]; // Same time regardless of array size
}

function dictLookup(obj, key) {
  return obj[key]; // Hash table average case
}

// O(log n) - Binary Search
function binarySearch(arr, target) {
  let left = 0, right = arr.length - 1;
  while (left <= right) {
    const mid = Math.floor((left + right) / 2);
    if (arr[mid] === target) return mid;
    if (arr[mid] < target) left = mid + 1;
    else right = mid - 1;
  }
  return -1;
}

// O(n) - Linear: Single iteration
function linearSearch(arr, target) {
  for (let i = 0; i < arr.length; i++) {
    if (arr[i] === target) return i;
  }
  return -1;
}

// O(n log n) - Merge Sort
function mergeSort(arr) {
  if (arr.length <= 1) return arr;
  const mid = Math.floor(arr.length / 2);
  const left = mergeSort(arr.slice(0, mid));
  const right = mergeSort(arr.slice(mid));
  return merge(left, right);
}

function merge(left, right) {
  const result = [];
  let i = 0, j = 0;
  while (i < left.length && j < right.length) {
    if (left[i] <= right[j]) {
      result.push(left[i++]);
    } else {
      result.push(right[j++]);
    }
  }
  return result.concat(left.slice(i), right.slice(j));
}

// O(n²) - Nested loops (Bubble Sort)
function bubbleSort(arr) {
  const n = arr.length;
  for (let i = 0; i < n; i++) {
    for (let j = 0; j < n - 1 - i; j++) {
      if (arr[j] > arr[j + 1]) {
        [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]];
      }
    }
  }
  return arr;
}

// O(n) Space - Hash Map for duplicates
function findDuplicates(arr) {
  const seen = new Set(); // O(n) space
  const duplicates = [];
  for (const num of arr) { // O(n) time
    if (seen.has(num)) {
      duplicates.push(num);
    } else {
      seen.add(num);
    }
  }
  return duplicates;
}

// Amortized O(1) - Dynamic Array (JavaScript arrays already do this)
class DynamicArray {
  constructor() {
    this.arr = new Array(1);
    this.size = 0;
  }

  append(val) {
    if (this.size === this.arr.length) {
      // O(n) operation, but amortized O(1) per append
      const newArr = new Array(this.arr.length * 2);
      for (let i = 0; i < this.size; i++) {
        newArr[i] = this.arr[i];
      }
      this.arr = newArr;
    }
    this.arr[this.size++] = val;
  }
}

// O(2^n) - Exponential: Naive Fibonacci
function fibNaive(n) {
  if (n <= 1) return n;
  return fibNaive(n - 1) + fibNaive(n - 2); // Exponential branches
}

// O(n) - Memoized Fibonacci
function fibMemo(n, memo = {}) {
  if (n in memo) return memo[n];
  if (n <= 1) return n;
  memo[n] = fibMemo(n - 1, memo) + fibMemo(n - 2, memo);
  return memo[n];
}

