# Amortized O(1) - Dynamic Array Growth
class DynamicArray:
    def __init__(self):
        self.arr = [0] * 1
        self.size = 0

    def append(self, val):
        if self.size == len(self.arr):
            # O(n) operation, but amortized O(1)
            new_arr = [0] * (2 * len(self.arr))
            for i in range(self.size):
                new_arr[i] = self.arr[i]
            self.arr = new_arr

        self.arr[self.size] = val
        self.size += 1

