    else right = mid;
  }
  return left;
}

// Upper bound - first element > target
function upperBound(arr, target) {
  let left = 0, right = arr.length;
  while (left < right) {
    const mid = left + Math.floor((right - left) / 2);
    if (arr[mid] <= target) left = mid + 1;
    else right = mid;
  }
  return left;
}

// Count occurrences of target
function countOccurrences(arr, target) {
  if (arr.length === 0) return 0;
  const leftIdx = lowerBound(arr, target);
  if (leftIdx >= arr.length || arr[leftIdx] !== target) return 0;
  const rightIdx = upperBound(arr, target);
  return rightIdx - leftIdx;
}

// Find range [start, end)
function findRange(arr, start, end) {
  const leftIdx = lowerBound(arr, start);
  const rightIdx = upperBound(arr, end - 1);
  return arr.slice(leftIdx, rightIdx);
}

// Recursive binary search (less preferred due to call stack)
function binarySearchRecursive(arr, target, left = 0, right = arr.length - 1) {
  if (left > right) return -1;
  const mid = left + Math.floor((right - left) / 2);
  if (arr[mid] === target) return mid;
  if (arr[mid] < target) return binarySearchRecursive(arr, target, mid + 1, right);
  return binarySearchRecursive(arr, target, left, mid - 1);
}

