  for (const neighbor of graph[node] || []) {
    if (!visited.has(neighbor)) {
      dfs(graph, neighbor, visited);
    }
  }
  return visited;
}

// BFS - Iterative with queue
function bfs(graph, start) {
  const visited = new Set([start]);
  const queue = [start];
  while (queue.length) {
    const node = queue.shift();
    for (const neighbor of graph[node] || []) {
      if (!visited.has(neighbor)) {
        visited.add(neighbor);
        queue.push(neighbor);
      }
    }
  }
  return visited;
}

// Dijkstra's Algorithm with min-heap (using array for simplicity)
function dijkstra(graph, start, n) {
  const dist = Array(n).fill(Infinity);
  dist[start] = 0;
  const heap = [[0, start]]; // [distance, node]

  while (heap.length) {
    heap.sort((a, b) => a[0] - b[0]);
    const [d, u] = heap.shift();

    if (d > dist[u]) continue;

    for (const [v, weight] of graph[u] || []) {
      if (dist[u] + weight < dist[v]) {
        dist[v] = dist[u] + weight;
        heap.push([dist[v], v]);
      }
    }
  }
  return dist;
}

// Bellman-Ford Algorithm (handles negative weights)
function bellmanFord(edges, n, start) {
  const dist = Array(n).fill(Infinity);
  dist[start] = 0;

  for (let i = 0; i < n - 1; i++) {
    for (const [u, v, weight] of edges) {
      if (dist[u] !== Infinity && dist[u] + weight < dist[v]) {
        dist[v] = dist[u] + weight;
      }
    }
  }

  // Check for negative cycle
  for (const [u, v, weight] of edges) {
    if (dist[u] !== Infinity && dist[u] + weight < dist[v]) {
      return null; // Negative cycle
    }
  }
  return dist;
}

// Topological Sort (DFS on DAG)
function topologicalSort(graph, n) {
  const visited = Array(n).fill(false);
  const stack = [];

  function dfsTopo(node) {
    visited[node] = true;
    for (const neighbor of graph[node] || []) {
      if (!visited[neighbor]) {
        dfsTopo(neighbor);
      }
    }
    stack.push(node);
  }

  for (let i = 0; i < n; i++) {
    if (!visited[i]) {
      dfsTopo(i);
    }
  }
  return stack.reverse();
}

// Union-Find for cycle detection
class UnionFind {
  constructor(n) {
    this.parent = Array.from({length: n}, (_, i) => i);
    this.rank = Array(n).fill(0);
  }

  find(x) {
    if (this.parent[x] !== x) {
      this.parent[x] = this.find(this.parent[x]); // Path compression
    }
    return this.parent[x];
  }

  union(x, y) {
    let px = this.find(x), py = this.find(y);
    if (px === py) return false; // Already connected
    if (this.rank[px] < this.rank[py]) [px, py] = [py, px];
    this.parent[py] = px;
    if (this.rank[px] === this.rank[py]) this.rank[px]++;
    return true;
  }
}

// Check for cycle in undirected graph
function hasCycleUndirected(n, edges) {
  const uf = new UnionFind(n);
  for (const [u, v] of edges) {
    if (!uf.union(u, v)) return true;
  }
  return false;
}

