# Graph Algorithms in Python

from collections import deque, defaultdict
import heapq

# DFS - Recursive
def dfs(graph, node, visited=None):
    """Depth-first search from node. O(V + E)."""
    if visited is None:
        visited = set()
    visited.add(node)
    for neighbor in graph[node]:
        if neighbor not in visited:
            dfs(graph, neighbor, visited)
    return visited

# BFS - Iterative with queue
def bfs(graph, start):
    """Breadth-first search from start. O(V + E)."""
    visited = {start}
    queue = deque([start])
    while queue:
        node = queue.popleft()
        for neighbor in graph[node]:
            if neighbor not in visited:
                visited.add(neighbor)
                queue.append(neighbor)
    return visited

# Dijkstra's Algorithm
def dijkstra(graph, start, n):
    """Shortest path from start. O((V + E) log V)."""
    dist = [float('inf')] * n
    dist[start] = 0
    heap = [(0, start)]  # (distance, node)

    while heap:
        d, u = heapq.heappop(heap)
        if d > dist[u]:
            continue
        for v, weight in graph[u]:
            if dist[u] + weight < dist[v]:
                dist[v] = dist[u] + weight
                heapq.heappush(heap, (dist[v], v))
    return dist

# Bellman-Ford Algorithm (handles negative weights)
def bellman_ford(edges, n, start):
    """Shortest path with negative weights. O(VE)."""
    dist = [float('inf')] * n
    dist[start] = 0

    for _ in range(n - 1):
        for u, v, weight in edges:
            if dist[u] != float('inf') and dist[u] + weight < dist[v]:
                dist[v] = dist[u] + weight

    # Check for negative cycle
    for u, v, weight in edges:
        if dist[u] != float('inf') and dist[u] + weight < dist[v]:
            return None  # Negative cycle detected
    return dist

# Topological Sort (DFS on DAG)
def topological_sort(graph, n):
    """Order nodes by dependencies. O(V + E)."""
    visited = [False] * n
    stack = []

    def dfs_topo(node):
        visited[node] = True
        for neighbor in graph[node]:
            if not visited[neighbor]:
                dfs_topo(neighbor)
        stack.append(node)  # Add after visiting neighbors

    for i in range(n):
        if not visited[i]:
            dfs_topo(i)

    return stack[::-1]  # Reverse

# Union-Find for cycle detection and connectivity
class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])  # Path compression
        return self.parent[x]

    def union(self, x, y):
        px, py = self.find(x), self.find(y)
        if px == py:
            return False  # Already connected
        if self.rank[px] < self.rank[py]:
            px, py = py, px
        self.parent[py] = px
        if self.rank[px] == self.rank[py]:
            self.rank[px] += 1
        return True

# Example: Cycle detection in undirected graph
def has_cycle_undirected(n, edges):
    """Check if undirected graph has cycle. O(E α(n))."""
    uf = UnionFind(n)
    for u, v in edges:
        if not uf.union(u, v):
            return True
    return False

