// Dynamic Programming in JavaScript

// 1. Fibonacci: Top-Down (Memoization)
function fibMemo(n, memo = {}) {
  if (n in memo) return memo[n];
  if (n <= 1) return n;
  memo[n] = fibMemo(n - 1, memo) + fibMemo(n - 2, memo);
  return memo[n];
}

// 2. Fibonacci: Bottom-Up (Tabulation)
function fibTab(n) {
  if (n <= 1) return n;
  const dp = Array(n + 1).fill(0);
  dp[1] = 1;
  for (let i = 2; i <= n; i++) {
    dp[i] = dp[i - 1] + dp[i - 2];
  }
  return dp[n];
}

// 3. Fibonacci: Space-Optimized
function fibOpt(n) {
  if (n <= 1) return n;
  let prev = 0, curr = 1;
  for (let i = 2; i <= n; i++) {
    [prev, curr] = [curr, prev + curr];
  }
  return curr;
}

// 4. Longest Increasing Subsequence (LIS)
function lis(arr) {
  if (arr.length === 0) return 0;
  const n = arr.length;
  const dp = Array(n).fill(1); // dp[i] = LIS ending at i
  for (let i = 1; i < n; i++) {
    for (let j = 0; j < i; j++) {
      if (arr[j] < arr[i]) {
        dp[i] = Math.max(dp[i], dp[j] + 1);
      }
    }
  }
  return Math.max(...dp);
}

// 5. Edit Distance (Levenshtein Distance)
function editDistance(s1, s2) {
  const m = s1.length, n = s2.length;
  const dp = Array(m + 1).fill(0).map(() => Array(n + 1).fill(0));

  // Base cases
  for (let i = 0; i <= m; i++) dp[i][0] = i;
  for (let j = 0; j <= n; j++) dp[0][j] = j;

  // Fill table
  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      if (s1[i - 1] === s2[j - 1]) {
        dp[i][j] = dp[i - 1][j - 1]; // No operation
      } else {
        dp[i][j] = 1 + Math.min(
          dp[i - 1][j],      // Delete
          dp[i][j - 1],      // Insert
          dp[i - 1][j - 1]   // Replace
        );
      }
    }
  }
  return dp[m][n];
}

// 6. 0/1 Knapsack Problem
function knapsack(capacity, weights, values) {
  const n = weights.length;
  const dp = Array(n + 1).fill(0).map(() => Array(capacity + 1).fill(0));

  for (let i = 1; i <= n; i++) {
    for (let w = 0; w <= capacity; w++) {
      if (weights[i - 1] <= w) {
        dp[i][w] = Math.max(
          values[i - 1] + dp[i - 1][w - weights[i - 1]], // Take
          dp[i - 1][w] // Skip
        );
      } else {
        dp[i][w] = dp[i - 1][w];
      }
    }
  }
  return dp[n][capacity];
}

// 7. Coin Change: Minimum coins
function coinChange(coins, amount) {
  const dp = Array(amount + 1).fill(Infinity);
  dp[0] = 0;

  for (let c = 1; c <= amount; c++) {
    for (const coin of coins) {
      if (coin <= c) {
        dp[c] = Math.min(dp[c], 1 + dp[c - coin]);
      }
    }
  }
  return dp[amount] === Infinity ? -1 : dp[amount];
}

// 8. Coin Change: Count ways
function coinChangeWays(coins, amount) {
  const dp = Array(amount + 1).fill(0);
  dp[0] = 1; // One way to make 0

  for (const coin of coins) {
    for (let c = coin; c <= amount; c++) {
      dp[c] += dp[c - coin];
    }
  }
  return dp[amount];
}

// Test cases
console.log("Fibonacci(10):", fibMemo(10)); // 55
console.log("LIS([10,9,2,5,3,7,101,18]):", lis([10, 9, 2, 5, 3, 7, 101, 18])); // 4
console.log("Edit distance('horse', 'ros'):", editDistance('horse', 'ros')); // 3
console.log("Knapsack(50, [10,20,30], [60,100,120]):", knapsack(50, [10, 20, 30], [60, 100, 120])); // 220
console.log("Coin change([1,2,5], 5):", coinChange([1, 2, 5], 5)); // 1
console.log("Coin ways([1,2,5], 5):", coinChangeWays([1, 2, 5], 5)); // 4


# Python
# Dynamic Programming in Python

# 1. Fibonacci: Top-Down (Memoization)
def fib_memo(n, memo=None):
    """Fibonacci with memoization. O(n) time, O(n) space."""
    if memo is None:
        memo = {}
    if n in memo:
        return memo[n]
    if n <= 1:
        return n
    memo[n] = fib_memo(n - 1, memo) + fib_memo(n - 2, memo)
    return memo[n]

# 2. Fibonacci: Bottom-Up (Tabulation)
def fib_tab(n):
    """Fibonacci iterative. O(n) time, O(n) space."""
    if n <= 1:
        return n
    dp = [0] * (n + 1)
    dp[1] = 1
    for i in range(2, n + 1):
        dp[i] = dp[i - 1] + dp[i - 2]
    return dp[n]

# 3. Fibonacci: Space-Optimized
def fib_opt(n):
    """Fibonacci with O(1) space (only store last 2 values)."""
    if n <= 1:
        return n
    prev, curr = 0, 1
    for _ in range(2, n + 1):
        prev, curr = curr, prev + curr
    return curr

# 4. Longest Increasing Subsequence (LIS)
def lis(arr):
    """LIS length. O(n^2) time, O(n) space."""
    if not arr:
        return 0
    n = len(arr)
    dp = [1] * n  # dp[i] = LIS ending at index i
    for i in range(1, n):
        for j in range(i):
            if arr[j] < arr[i]:
                dp[i] = max(dp[i], dp[j] + 1)
    return max(dp)

# 5. Edit Distance (Levenshtein Distance)
def edit_distance(s1, s2):
    """Min edits (insert, delete, replace). O(mn) time."""
    m, n = len(s1), len(s2)
    dp = [[0] * (n + 1) for _ in range(m + 1)]

    # Base cases
    for i in range(m + 1):
        dp[i][0] = i  # Delete all chars from s1
    for j in range(n + 1):
        dp[0][j] = j  # Insert all chars from s2

    # Fill table
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if s1[i - 1] == s2[j - 1]:
                dp[i][j] = dp[i - 1][j - 1]  # No operation needed
            else:
                dp[i][j] = 1 + min(
                    dp[i - 1][j],      # Delete from s1
                    dp[i][j - 1],      # Insert into s1
                    dp[i - 1][j - 1]   # Replace
                )
    return dp[m][n]

# 6. 0/1 Knapsack Problem
def knapsack(capacity, weights, values):
    """0/1 knapsack. O(nW) time, O(nW) space."""
    n = len(weights)
    dp = [[0] * (capacity + 1) for _ in range(n + 1)]

    for i in range(1, n + 1):
        for w in range(capacity + 1):
            if weights[i - 1] <= w:
                # Either take item or skip it
                dp[i][w] = max(
                    values[i - 1] + dp[i - 1][w - weights[i - 1]],  # Take
                    dp[i - 1][w]  # Skip
                )
            else:
                dp[i][w] = dp[i - 1][w]  # Can't fit, skip
    return dp[n][capacity]

# 7. Coin Change: Minimum coins
def coin_change(coins, amount):
    """Min coins to make amount. O(nC) time, O(C) space."""
    dp = [float('inf')] * (amount + 1)
    dp[0] = 0  # 0 coins to make amount 0

    for c in range(1, amount + 1):
        for coin in coins:
            if coin <= c:
                dp[c] = min(dp[c], 1 + dp[c - coin])

    return dp[amount] if dp[amount] != float('inf') else -1

# 8. Coin Change: Count ways
def coin_change_ways(coins, amount):
    """Count ways to make amount. O(nC) time."""
    dp = [0] * (amount + 1)
    dp[0] = 1  # One way to make 0: use no coins

    for coin in coins:
        for c in range(coin, amount + 1):
            dp[c] += dp[c - coin]
    return dp[amount]

# Test cases
if __name__ == "__main__":
    print("Fibonacci(10):", fib_memo(10))  # 55
    print("LIS([10,9,2,5,3,7,101,18]):", lis([10, 9, 2, 5, 3, 7, 101, 18]))  # 4 ([2,3,7,101])
    print("Edit distance('horse', 'ros'):", edit_distance('horse', 'ros'))  # 3
    print("Knapsack(50, [10,20,30], [60,100,120]):", knapsack(50, [10, 20, 30], [60, 100, 120]))  # 220
    print("Coin change([1,2,5], 5):", coin_change([1, 2, 5], 5))  # 1 (one 5-coin)
    print("Coin ways([1,2,5], 5):", coin_change_ways([1, 2, 5], 5))  # 4

