// Rust example: Async Snowflake query handler for high-performance backends
use snowflake_api::connection::SnowflakeConnection;
use tokio::sync::RwLock;
use std::sync::Arc;
use serde::{Deserialize, Serialize};

#[derive(Serialize, Deserialize, Clone)]
pub struct QueryRequest {
    pub query: String,
    pub timeout_seconds: u32,
}

pub struct SnowflakePool {
    connections: Arc<RwLock<Vec<SnowflakeConnection>>>,
}

impl SnowflakePool {
    pub async fn new(size: usize, config: SnowflakeConfig) -> Result<Self, Box<dyn std::error::Error>> {
        let mut connections = Vec::new();
        for _ in 0..size {
            connections.push(SnowflakeConnection::new(&config).await?);
        }
        Ok(SnowflakePool {
            connections: Arc::new(RwLock::new(connections)),
        })
    }

    pub async fn execute_query(&self, request: QueryRequest) -> Result<Vec<serde_json::Value>, String> {
        let mut conns = self.connections.write().await;
        if let Some(conn) = conns.pop() {
            match tokio::time::timeout(
                std::time::Duration::from_secs(request.timeout_seconds as u64),
                conn.execute(&request.query),
            ).await {
                Ok(Ok(results)) => {
                    conns.push(conn); // Return connection to pool
                    Ok(results)
                }
                Ok(Err(e)) => Err(format!("Query error: {}", e)),
                Err(_) => Err("Query timeout".to_string()),
            }
        } else {
            Err("No available connections".to_string())
        }
    }
}


