#include <iostream>
#include <curl/curl.h>
#include <json/json.h>

class SnowflakeConnector {
private:
    std::string account_id;
    std::string warehouse;
    std::string database;
    std::string auth_token;

public:
    SnowflakeConnector(const std::string& acc, const std::string& wh,
                       const std::string& db, const std::string& token)
        : account_id(acc), warehouse(wh), database(db), auth_token(token) {}

    std::string executeQuery(const std::string& query) {
        std::string url = "https://" + account_id + ".snowflakecomputing.com/api/v2/statements";
        CURL* curl = curl_easy_init();
        if (!curl) return "";
        struct curl_slist* headers = nullptr;
        headers = curl_slist_append(headers, "Content-Type: application/json");
        headers = curl_slist_append(headers, ("Authorization: Bearer " + auth_token).c_str());
        Json::Value request_body;
        request_body["statement"] = query;
        curl_easy_setopt(curl, CURLOPT_URL, url.c_str());
        curl_easy_setopt(curl, CURLOPT_HTTPHEADER, headers);
        curl_easy_perform(curl);
        curl_slist_free_all(headers);
        curl_easy_cleanup(curl);
        return "";
    }
};

