// Rust Example
use std::collections::HashMap;

#[derive(Clone, PartialEq)]
enum UserRole {
    Admin,
    Editor,
    Viewer,
}

struct User {
    username: String,
    password_hash: String,
    role: UserRole,
    authenticated: bool,
}

impl User {
    fn new(username: &str, password: &str, role: UserRole) -> Self {
        User {
            username: username.to_string(),
            password_hash: format!("{:x}", md5::compute(password.as_bytes())),
            role,
            authenticated: false,
        }
    }

    /// Authentication: verify identity
    fn authenticate(&mut self, password: &str) -> bool {
        let hash = format!("{:x}", md5::compute(password.as_bytes()));
        if hash == self.password_hash {
            self.authenticated = true;
            return true;
        }
        false
    }

    /// Authorization: check if user can perform action
    fn is_authorized(&self, action: &str) -> bool {
        if !self.authenticated {
            return false;
        }

        let mut permissions: HashMap<UserRole, Vec<&str>> = HashMap::new();
        permissions.insert(UserRole::Admin, vec!["read", "write", "delete", "manage_users"]);
        permissions.insert(UserRole::Editor, vec!["read", "write"]);
        permissions.insert(UserRole::Viewer, vec!["read"]);

        permissions
            .get(&self.role)
            .map(|perms| perms.contains(&action))
            .unwrap_or(false)
    }
}

fn main() {
    let mut user = User::new("alice", "secret123", UserRole::Editor);

    if user.authenticate("secret123") {
        println!("✓ Authentication successful");
        if user.is_authorized("write") {
            println!("✓ Authorization granted - can write");
        }
        if !user.is_authorized("manage_users") {
            println!("✗ Authorization denied - cannot manage users");
        }
    } else {
        println!("✗ Authentication failed");
    }
}

# JavaScript
// Cloudflare Worker: authentication + rate limiting + caching
export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const cacheKey = new Request(url.toString(), { method: 'GET' });
    const cache = caches.default;

    // Check cache first
    let response = await cache.match(cacheKey);
    if (response) return response;

    // Check auth header
    const token = request.headers.get('Authorization');
    if (!token) {
      return new Response('Unauthorized', { status: 401 });
    }

    // Rate limiting: use KV to track requests per IP
    const ip = request.headers.get('CF-Connecting-IP');
    const rateLimitKey = `ratelimit:${ip}`;
    const count = await env.KV.get(rateLimitKey) || '0';

    if (parseInt(count) > 100) {
      return new Response('Rate limited', { status: 429 });
    }

    // Increment counter with 1-hour TTL
    await env.KV.put(rateLimitKey, String(parseInt(count) + 1), { expirationTtl: 3600 });

    // Forward to origin
    response = await fetch(request);

    // Cache successful responses for 1 hour
    if (response.status === 200) {
      response = new Response(response.body, response);
      response.headers.set('Cache-Control', 'max-age=3600');
      await cache.put(cacheKey, response.clone());
    }

    return response;
  }
};

