        self.cache = cache_store

    async def handle_request(self, request, origin_url):
        # Check cache
        cache_key = hashlib.md5(str(request.url).encode()).hexdigest()
        cached = await self.cache.get(cache_key)
        if cached:
            return cached

        # Validate auth
        token = request.headers.get('Authorization')
        if not token:
            return {'status': 401, 'body': 'Unauthorized'}

        # Rate limiting
        ip = request.headers.get('CF-Connecting-IP')
        rate_limit_key = f'ratelimit:{ip}'
        count = int(await self.kv.get(rate_limit_key) or 0)

        if count > 100:
            return {'status': 429, 'body': 'Rate limited'}

        # Increment counter
        await self.kv.put(
            rate_limit_key,
            str(count + 1),
            ttl=3600
        )

        # Forward to origin
        response = await fetch(origin_url, request)

        # Cache if successful
        if response['status'] == 200:
            await self.cache.put(cache_key, response, ttl=3600)

        return response

# Go
package main

import (
	"fmt"
	"net/http"
	"strconv"
	"time"
)

type WorkerHandler struct {
	KVStore   KVInterface
	CacheAPI  CacheInterface
}

type KVInterface interface {
	Get(ctx context.Context, key string) (string, error)
	Put(ctx context.Context, key string, value string, ttl time.Duration) error
}

type CacheInterface interface {
	Get(ctx context.Context, key string) ([]byte, error)
	Put(ctx context.Context, key string, value []byte, ttl time.Duration) error
}

func (w *WorkerHandler) ServeHTTP(resp http.ResponseWriter, req *http.Request) {
	ctx := req.Context()

	// Check cache
	cacheKey := hashRequest(req)
	if cached, err := w.CacheAPI.Get(ctx, cacheKey); err == nil {
		resp.Write(cached)
		return
	}

	// Validate auth
	token := req.Header.Get("Authorization")
	if token == "" {
		resp.WriteHeader(http.StatusUnauthorized)
		fmt.Fprintf(resp, "Unauthorized")
		return
	}

	// Rate limiting
	ip := req.Header.Get("CF-Connecting-IP")
	rateLimitKey := fmt.Sprintf("ratelimit:%s", ip)
	countStr, _ := w.KVStore.Get(ctx, rateLimitKey)
	count, _ := strconv.Atoi(countStr)

	if count > 100 {
		resp.WriteHeader(http.StatusTooManyRequests)
		fmt.Fprintf(resp, "Rate limited")
		return
	}

	// Increment counter
	w.KVStore.Put(ctx, rateLimitKey, strconv.Itoa(count+1), time.Hour)
}

# Rust
use wasm_bindgen::prelude::*;
use web_sys::{Request, Response};

#[wasm_bindgen]
pub struct CloudflareWorker {
    kv_store: KVStore,
}

#[wasm_bindgen]
impl CloudflareWorker {
    #[wasm_bindgen(constructor)]
    pub fn new() -> CloudflareWorker {
        CloudflareWorker {
            kv_store: KVStore::new(),
        }
    }

    pub async fn fetch(&self, request: Request) -> Result<Response, JsValue> {
        // Check cache
        let cache_key = hash_request(&request);
        if let Some(cached) = self.get_cache(&cache_key).await? {
            return Ok(cached);
        }

        // Validate auth
        let headers = request.headers();
        let token = headers.get("Authorization")
            .ok_or_else(|| JsValue::from_str("Unauthorized"))?;

        if token.is_empty() {
            return Err(JsValue::from_str("Unauthorized"));
        }

        // Rate limiting
        let ip = headers.get("CF-Connecting-IP")
            .unwrap_or_else(|_| "unknown".to_string());
        let rate_limit_key = format!("ratelimit:{}", ip);

        let count: u32 = self.kv_store
            .get(&rate_limit_key)
            .await?
            .unwrap_or_else(|| "0".to_string())
            .parse()
            .unwrap_or(0);

        if count > 100 {
            return Err(JsValue::from_str("Rate limited"));
        }

        // Increment counter
        self.kv_store
            .put(&rate_limit_key, &(count + 1).to_string(), 3600)
            .await?;

        // Forward to origin
        let response = fetch_request(&request).await?;

        // Cache successful responses
        if response.status() == 200 {
            self.put_cache(&cache_key, &response).await?;
        }

        Ok(response)
    }
