using namespace emscripten;

class CloudflareWorker {
private:
    std::map<std::string, std::pair<std::string, long>> kv_cache;
    long current_time;

public:
    CloudflareWorker() : current_time(0) {}

    bool validate_auth(const std::string& token) {
        return token.length() > 0 && token.substr(0, 7) == "Bearer ";
    }

    bool check_rate_limit(const std::string& ip, int max_requests) {
        std::string key = "ratelimit:" + ip;

        auto it = kv_cache.find(key);
        if (it != kv_cache.end()) {
            int count = std::stoi(it->second.first);
            long expires_at = it->second.second;

            if (current_time < expires_at) {
                if (count > max_requests) {
                    return false;
                }
                kv_cache[key] = {std::to_string(count + 1), expires_at};
                return true;
            }
        }

        long expires_at = current_time + 3600;
        kv_cache[key] = {"1", expires_at};
        return true;
    }
}

