#include <iostream>
#include <memory>
#include <string>

class Subject {
public:
    virtual ~Subject() = default;
    virtual std::string request() = 0;
};

class RealSubject : public Subject {
private:
    std::string data;
    std::string expensiveOperation() {
        std::cout << "Loading expensive resource..." << std::endl;
        return "Heavy Data";
    }
public:
    RealSubject() : data(expensiveOperation()) {}
    std::string request() override { return data; }
};

class ProxySubject : public Subject {
private:
    mutable std::shared_ptr<RealSubject> realSubject;
public:
    std::string request() override {
        if (!realSubject) {
            realSubject = std::make_shared<RealSubject>();
        }
        return realSubject->request();
    }
};

int main() {
    ProxySubject proxy;
    std::cout << proxy.request() << std::endl;  // Creates RealSubject
    std::cout << proxy.request() << std::endl;  // Reuses cached
    return 0;
}
