use std::cell::RefCell;
use std::rc::Rc;

trait Subject {
    fn request(&self) -> &str;
}

struct RealSubject {
    data: String,
}

impl RealSubject {
    fn new() -> Self {
        println!("Loading expensive resource...");
        RealSubject {
            data: "Heavy Data".to_string(),
        }
    }
}

impl Subject for RealSubject {
    fn request(&self) -> &str {
        &self.data
    }
}

struct ProxySubject {
    real_subject: RefCell<Option<Rc<RealSubject>>>,
}

impl ProxySubject {
    fn new() -> Self {
        ProxySubject {
            real_subject: RefCell::new(None),
        }
    }
}

impl Subject for ProxySubject {
    fn request(&self) -> &str {
        let mut subject = self.real_subject.borrow_mut();
        if subject.is_none() {
            *subject = Some(Rc::new(RealSubject::new()));
        }
        subject.as_ref().unwrap().request()
    }
}

fn main() {
    let proxy = ProxySubject::new();
    println!("{}", proxy.request());  // Creates RealSubject on first call
    println!("{}", proxy.request());  // Reuses cached
}
