// Trade-off: responsibility on programmer

#include <thread>
#include <mutex>
#include <vector>
#include <iostream>

std::mutex mtx;  // Manual mutex (like Python's Lock)
int counter = 0;

void worker() {
    // Lock explicitly (no automatic GIL)
    std::lock_guard<std::mutex> lock(mtx);
    counter++;  // Protected section
}  // Lock automatically released

int main() {
    std::vector<std::thread> threads;

    // True parallelism on multi-core
    for (int i = 0; i < 10; ++i) {
        threads.emplace_back(worker);
    }

    for (auto& t : threads) {
        t.join();
    }

    std::cout << "Counter: " << counter << std::endl;  // 10
    // Responsibility: correct locking, avoid deadlocks
    // Benefit: no GIL overhead, true parallelism
    return 0;
