import boto3
import json
from typing import Any

# Initialize Bedrock client
bedrock_client = boto3.client('bedrock-agent-runtime')

class BedrockAgentExample:
    def __init__(self, agent_id: str, agent_alias_id: str):
        self.agent_id = agent_id
        self.agent_alias_id = agent_alias_id
        self.session_id = "session-123"

    def invoke_agent(self, user_input: str, session_id: str = None) -> dict:
        """
        Invoke an agent to process user input and perform actions.
        """
        if session_id:
            self.session_id = session_id

        try:
            response = bedrock_client.invoke_agent(
                agentId=self.agent_id,
                agentAliasId=self.agent_alias_id,
                sessionId=self.session_id,
                inputText=user_input
            )

            # Process streaming response
            result_text = ""
            event_stream = response.get('completion')

            for event in event_stream:
                if 'chunk' in event:
                    chunk = event['chunk']
                    if 'bytes' in chunk:
                        result_text += chunk['bytes'].decode('utf-8')

            return {
                'success': True,
                'response': result_text,
                'session_id': self.session_id
            }

        except Exception as e:
            return {
                'success': False,
                'error': str(e)
            }

    def get_agent_info(self) -> dict:
        """
        Retrieve agent configuration and metadata.
        """
        try:
            response = bedrock_client.get_agent(
                agentId=self.agent_id
            )

            return {
                'agent_id': response['agent']['id'],
                'name': response['agent']['name'],
                'description': response['agent']['description'],
                'foundation_model': response['agent']['foundationModel'],
                'instruction': response['agent']['instruction'],
                'status': response['agent']['agentStatus']
            }

        except Exception as e:
            return {'error': str(e)}

