#include <iostream>
#include <cmath>
#include <iomanip>

struct CapacityEstimate {
    double write_qps;
    double read_qps;
    double peak_read_qps;
    long long total_urls;
    double storage_tb;
    double storage_with_replication_tb;
    double cache_size_gb;
    int app_servers;
    int db_shards;
};

CapacityEstimate estimateCapacity(long long urlsPerMonth, int years = 5, double readWriteRatio = 100.0) {
    const double SECONDS_PER_MONTH = 30 * 24 * 3600;
    const long long BYTES_PER_URL = 2500; // 2KB URL + 500B metadata
    const long long BYTES_PER_GB = 1024LL * 1024 * 1024;
    const long long BYTES_PER_TB = BYTES_PER_GB * 1024;

    // Traffic calculations
    double writeQps = static_cast<double>(urlsPerMonth) / SECONDS_PER_MONTH;
    double readQps = writeQps * readWriteRatio;
    double peakReadQps = readQps * 3.0;

    // Storage calculations
    long long totalUrls = urlsPerMonth * 12 * years;
    long long totalStorageBytes = totalUrls * BYTES_PER_URL;
    double storageTb = static_cast<double>(totalStorageBytes) / BYTES_PER_TB;
    double withReplicationTb = storageTb * 3.0;

    // Caching (1% of URLs as hot data)
    long long cacheUrls = totalUrls / 100;
    double cacheSizeGb = static_cast<double>(cacheUrls * BYTES_PER_URL) / BYTES_PER_GB;

    // Infrastructure sizing
    int appServers = std::max(10, static_cast<int>(std::ceil(readQps / 1000.0)));
    int dbShards = static_cast<int>(std::ceil(static_cast<double>(totalUrls) / 1e9));

    return {
        writeQps,
        readQps,
        peakReadQps,
        totalUrls,
        storageTb,
        withReplicationTb,
        cacheSizeGb,
        appServers,
        dbShards
    };
}

int main() {
    auto results = estimateCapacity(500'000'000);

    std::cout << std::fixed << std::setprecision(1);
    std::cout << "Write QPS: " << results.write_qps << std::endl;
    std::cout << "Read QPS: " << results.read_qps << std::endl;
    std::cout << "Peak Read QPS: " << results.peak_read_qps << std::endl;
    std::cout << std::setprecision(0);
    std::cout << "Storage: " << results.storage_tb << "TB (replicated: " 
              << results.storage_with_replication_tb << "TB)" << std::endl;
    std::cout << "Cache: " << results.cache_size_gb << "GB" << std::endl;
    std::cout << "App servers: " << results.app_servers << std::endl;
    std::cout << "DB shards: " << results.db_shards << std::endl;

    return 0;
}


