  const writeBandwidthKbps = writeQps * (bytesPerUrl / 1024);
  const readBandwidthKbps = readQps * (2000 / 1024); // 2KB response

  // Caching (1% of URLs as hot data)
  const cacheUrls = Math.floor(totalUrls * 0.01);
  const cacheSizeGb = (cacheUrls * bytesPerUrl) / Math.pow(1024, 3);

