def estimate_capacity(urls_per_month, years=5, read_write_ratio=100):
    """Estimate capacity requirements for URL shortening service."""
    seconds_per_month = 30 * 24 * 3600

    # Traffic calculations
    write_qps = urls_per_month / seconds_per_month
    read_qps = write_qps * read_write_ratio
    peak_write_qps = write_qps * 3  # 3x peak factor
    peak_read_qps = read_qps * 3

    # Storage calculations
    total_urls = urls_per_month * 12 * years
    bytes_per_url = 2500  # 2KB URL + 500B metadata
    total_storage_bytes = total_urls * bytes_per_url
    total_storage_tb = total_storage_bytes / (1024**4)
    with_replication_tb = total_storage_tb * 3

    # Bandwidth
    write_bandwidth_kbps = write_qps * (bytes_per_url / 1024)
    read_bandwidth_kbps = read_qps * 2000 / 1024  # 2KB response

    # Caching (1% of URLs, hot data)
    cache_urls = int(total_urls * 0.01)
    cache_size_gb = (cache_urls * bytes_per_url) / (1024**3)

    return {
        'write_qps': write_qps,
        'read_qps': read_qps,
        'peak_write_qps': peak_write_qps,
        'peak_read_qps': peak_read_qps,
        'total_urls': total_urls,
        'storage_tb': total_storage_tb,
        'storage_with_replication_tb': with_replication_tb,
        'write_bandwidth_kbps': write_bandwidth_kbps,
        'read_bandwidth_kbps': read_bandwidth_kbps,
        'cache_size_gb': cache_size_gb,
        'app_servers': max(10, int(read_qps / 1000))
    }

