    years: u32,
    read_write_ratio: f64,
) -> CapacityEstimate {
    const SECONDS_PER_MONTH: f64 = 30.0 * 24.0 * 3600.0;
    const BYTES_PER_URL: u64 = 2500; // 2KB URL + 500B metadata
    const BYTES_PER_GB: u64 = 1024 * 1024 * 1024;
    const BYTES_PER_TB: u64 = BYTES_PER_GB * 1024;

    // Traffic calculations
    let write_qps = urls_per_month as f64 / SECONDS_PER_MONTH;
    let read_qps = write_qps * read_write_ratio;
    let peak_read_qps = read_qps * 3.0;

    // Storage calculations
    let total_urls = urls_per_month as u64 * 12 * years as u64;
    let total_storage_bytes = total_urls * BYTES_PER_URL;
    let storage_tb = total_storage_bytes as f64 / BYTES_PER_TB as f64;
    let with_replication_tb = storage_tb * 3.0;

    // Caching (1% of URLs as hot data)
    let cache_urls = total_urls / 100;
    let cache_size_gb = (cache_urls * BYTES_PER_URL) as f64 / BYTES_PER_GB as f64;

    // Infrastructure sizing
    let app_servers = ((read_qps / 1000.0).ceil() as u32).max(10);
    let db_shards = ((total_urls as f64 / 1e9).ceil()) as u32;

    CapacityEstimate {
        write_qps,
        read_qps,
        peak_read_qps,
        total_urls,
        storage_tb,
        with_replication_tb,
        cache_size_gb,
        app_servers,
        db_shards,
    }
}

struct CapacityEstimate {
    write_qps: f64,
    read_qps: f64,
    peak_read_qps: f64,
    total_urls: u64,
    storage_tb: f64,
    with_replication_tb: f64,
    cache_size_gb: f64,
    app_servers: u32,
    db_shards: u32,
}

fn main() {
    let results = estimate_capacity(500_000_000, 5, 100.0);
    println!("Write QPS: {:.1}", results.write_qps);
    println!("Read QPS: {:.0}", results.read_qps);
    println!("Peak Read QPS: {:.0}", results.peak_read_qps);
    println!(
        "Storage: {:.0}TB (replicated: {:.0}TB)",
        results.storage_tb, results.with_replication_tb
    );
    println!("Cache: {:.0}GB", results.cache_size_gb);
    println!("App servers: {}", results.app_servers);
    println!("DB shards: {}", results.db_shards);
}


