const cassandra = require('cassandra-driver');

const client = new cassandra.Client({
  contactPoints: ['127.0.0.1'],
  keyspace: 'social'
});

async function setupAndInsert() {
  await client.connect();

  // Create keyspace
  await client.execute(
    `CREATE KEYSPACE IF NOT EXISTS social WITH 
     replication = {'class': 'SimpleStrategy', 'replication_factor': 3}`
  );

  // Create table
  await client.execute(`
    CREATE TABLE IF NOT EXISTS social.posts_by_user (
      user_id UUID PRIMARY KEY,
      post_id UUID,
      created_at TIMESTAMP,
      content TEXT,
      likes INT
    )
  `);

  // Insert with QUORUM consistency
  const query = `
    INSERT INTO social.posts_by_user 
    (user_id, post_id, created_at, content) 
    VALUES (?, ?, ?, ?)
  `;

  const { v4: uuid } = require('uuid');
  const userId = uuid();
  const postId = uuid();

  await client.execute(query, 
    [userId, postId, new Date(), 'Hello, world!'],
    { consistency: cassandra.types.consistencyLevels.quorum }
  );

  // Read with QUORUM consistency
  const readQuery = `SELECT * FROM social.posts_by_user WHERE user_id = ?`;
  const result = await client.execute(
    readQuery,
    [userId],
    { consistency: cassandra.types.consistencyLevels.quorum }
  );

  result.rows.forEach(row => {
    console.log(`Post ${row.post_id}: ${row.content}`);
  });

  await client.shutdown();
}

setupAndInsert().catch(console.error);

