// Cassandra C++ driver example (using cpp-driver)
#include <cassandra.h>
#include <iostream>
#include <uuid/uuid.h>

int main() {
  // Create cluster and connect
  CassCluster* cluster = cass_cluster_new();
  CassSession* session = cass_session_new();

  cass_cluster_set_contact_points(cluster, "127.0.0.1");

  CassFuture* connect_future = cass_session_connect(session, cluster);

  if (cass_future_error_code(connect_future) == CASS_OK) {
    // Create keyspace
    const char* create_keyspace = 
      "CREATE KEYSPACE IF NOT EXISTS social WITH "
      "replication = {'class': 'SimpleStrategy', 'replication_factor': 3}";

    CassFuture* future = cass_session_execute_query(session, create_keyspace);
    cass_future_free(future);

    // Create table
    const char* create_table = 
      "CREATE TABLE IF NOT EXISTS social.posts_by_user ("
      "user_id UUID PRIMARY KEY, "
      "post_id UUID, "
      "created_at TIMESTAMP, "
      "content TEXT, "
      "likes INT)";

    future = cass_session_execute_query(session, create_table);
    cass_future_free(future);

    // Prepared statement for insert with QUORUM
    CassStatement* insert_stmt = cass_statement_new(
      "INSERT INTO social.posts_by_user (user_id, post_id, created_at, content) "
      "VALUES (?, ?, ?, ?)", 4);

    cass_statement_set_consistency(insert_stmt, CASS_CONSISTENCY_QUORUM);

    // Bind values (simplified UUID handling)
    CassUuid user_id = {};
    CassUuid post_id = {};
    cass_uuid_gen_time(nullptr, user_id.time_and_version);
    cass_uuid_gen_time(nullptr, post_id.time_and_version);

    cass_statement_bind_uuid(insert_stmt, 0, user_id);
    cass_statement_bind_uuid(insert_stmt, 1, post_id);
    cass_statement_bind_int64(insert_stmt, 2, cass_timestamp_gen_monotonic());
    cass_statement_bind_string(insert_stmt, 3, "Hello, world!");

    future = cass_session_execute(session, insert_stmt);
    cass_statement_free(insert_stmt);

    if (cass_future_error_code(future) == CASS_OK) {
      std::cout << "Insert successful" << std::endl;
    }
    cass_future_free(future);
  }

  cass_session_close(session);
  cass_cluster_free(cluster);
  cass_session_free(session);

  return 0;
}

