// Cassandra Rust driver (cdrs-tokio)
use cdrs_tokio::cluster::ClusterTcpBuilder;
use cdrs_tokio::load_balancing::RoundRobin;
use cdrs_tokio::query::QueryExecutor;
use cdrs_tokio::frame::Version;
use uuid::Uuid;
use chrono::Utc;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Create cluster with round-robin load balancing
    let cluster = ClusterTcpBuilder::new()
        .add_contact_point("127.0.0.1:9042")
        .build_with_load_balancing_policy(RoundRobin::new())
        .await?;

    let session = cluster.connect().await?;

    // Create keyspace
    let create_keyspace = 
        "CREATE KEYSPACE IF NOT EXISTS social WITH \
         replication = {'class': 'SimpleStrategy', 'replication_factor': 3}";
    session.query(create_keyspace).await?;

    // Create table
    let create_table = 
        "CREATE TABLE IF NOT EXISTS social.posts_by_user (\
         user_id UUID PRIMARY KEY, \
         post_id UUID, \
         created_at TIMESTAMP, \
         content TEXT, \
         likes INT)";
    session.query(create_table).await?;

    // Insert with QUORUM consistency
    let insert_query = 
        "INSERT INTO social.posts_by_user \
         (user_id, post_id, created_at, content) \
         VALUES (?, ?, ?, ?)";

    let user_id = Uuid::new_v4();
    let post_id = Uuid::new_v4();
    let now = Utc::now();

    session
        .query(insert_query)
        .param(user_id)
        .param(post_id)
        .param(now)
        .param("Hello, world!")
        .execute()
        .await?;

    // Read with QUORUM
    let read_query = "SELECT * FROM social.posts_by_user WHERE user_id = ?";
    let rows = session
        .query(read_query)
        .param(user_id)
        .execute()
        .await?;

    println!("Retrieved {} posts", rows.len());

    Ok(())
}

