// Cassandra Go driver (gocql)
package main

import (
	"fmt"
	"log"
	"time"
	"github.com/gocql/gocql"
)

func main() {
	// Create cluster
	cluster := gocql.NewCluster("127.0.0.1")
	cluster.Keyspace = "social"
	cluster.Consistency = gocql.Quorum
	cluster.ProtoVersion = 4

	session, err := cluster.CreateSession()
	if err != nil {
		log.Fatal(err)
	}
	defer session.Close()

	// Create keyspace
	err = session.Query(
		`CREATE KEYSPACE IF NOT EXISTS social WITH 
		 replication = {'class': 'SimpleStrategy', 'replication_factor': 3}`,
	).Exec()
	if err != nil {
		log.Fatal(err)
	}

	// Create table
	err = session.Query(`
		CREATE TABLE IF NOT EXISTS social.posts_by_user (
			user_id UUID,
			created_at TIMESTAMP,
			post_id UUID,
			content TEXT,
			likes INT,
			PRIMARY KEY (user_id, created_at)
		)
		WITH CLUSTERING ORDER BY (created_at DESC)
	`).Exec()
	if err != nil {
		log.Fatal(err)
	}

	// Insert with QUORUM consistency
	userID := gocql.TimeUUID()
	postID := gocql.TimeUUID()
	now := time.Now()

	if err := session.Query(
		`INSERT INTO social.posts_by_user 
		 (user_id, post_id, created_at, content) 
		 VALUES (?, ?, ?, ?)`,
		userID, postID, now, "Hello, world!",
	).Exec(); err != nil {
		log.Fatal(err)
	}

	// Read with QUORUM consistency
	type Post struct {
		UserID    gocql.UUID
		PostID    gocql.UUID
		CreatedAt time.Time
		Content   string
		Likes     int
	}

	var posts []Post
	iter := session.Query(
		`SELECT user_id, post_id, created_at, content, likes 
		 FROM social.posts_by_user 
		 WHERE user_id = ?`,
		userID,
	).Iter()

	var post Post
	for iter.Scan(&post.UserID, &post.PostID, &post.CreatedAt, &post.Content, &post.Likes) {
		posts = append(posts, post)
		fmt.Printf("Post %s: %s (likes: %d)\n", post.PostID, post.Content, post.Likes)
	}

	if err := iter.Close(); err != nil {
		log.Fatal(err)
	}

	fmt.Printf("Retrieved %d posts\n", len(posts))
}

