# Operator pattern: watch CRD, reconcile state
from kopf import on_event
from kubernetes import client, config

@on_event("v1", "databases", labels={"env": "prod"})
def on_database_create(spec, name, namespace, **kwargs):
    """When Database CRD created, provision PostgreSQL"""
    # Create StatefulSet
    stateful_set = {
        "apiVersion": "apps/v1",
        "kind": "StatefulSet",
        "metadata": {"name": f"postgres-{name}"},
        "spec": {
            "serviceName": f"postgres-{name}",
            "replicas": spec.get("replicas", 1),
            "selector": {"matchLabels": {"db": name}},
            "template": {
                "metadata": {"labels": {"db": name}},
                "spec": {
                    "containers": [{
                        "name": "postgres",
                        "image": f"postgres:{spec[\"version\"]}",
                        "volumeMounts": [{"name": "data", "mountPath": "/var/lib/postgresql"}]
                    }]
                },
                "volumeClaimTemplates": [{
                    "metadata": {"name": "data"},
                    "spec": {
                        "storageClassName": "fast-ssd",
                        "resources": {"requests": {"storage": spec.get("storage", "10Gi")}}
                    }
                }]
            }
        }
    }

    # Create backup CronJob
    api = client.AppsV1Api()
    api.create_namespaced_stateful_set(namespace, stateful_set)

